import { User, UserRole, BloodStock, DonationRequest, Feedback, Hospital, Campaign, Achievement, Appointment, BloodRequest, DonorCertificate, EmergencyKey, SecurityLog } from "../types";
import { DB } from "./db";

// Simulated Latency helper
const delay = (ms: number = 800) => new Promise(resolve => setTimeout(resolve, ms));

export const API = {
  // --- AUTH API ---
  login: async (username: string, password: string, role: UserRole): Promise<User | null> => {
    await delay(1000); // Simulate network roundtrip
    const users = DB.getUsers();

    // In a real app, passwords would be hashed. 
    // For this build, we follow the "rajput/rajput" and "singh/singh" mock patterns
    const foundUser = users.find(u => u.username === username && u.role === role);

    if (foundUser) {
      const isValid = (username === 'rajput' && password === 'rajput') || 
                      (password === 'singh'); // General mock rule for donors/users
      return isValid ? foundUser : null;
    }
    return null;
  },

  register: async (userData: Partial<User>): Promise<User> => {
    await delay(1200);
    const users = DB.getUsers();
    const newUser: User = {
      id: `u-${Date.now()}`,
      username: userData.username || '',
      name: userData.name || '',
      role: userData.role || UserRole.USER,
      joinDate: new Date().toISOString().split('T')[0],
      status: 'Active',
      ...userData
    };
    users.push(newUser);
    DB.saveUsers(users);
    return newUser;
  },

  // --- USER API ---
  updateUser: async (updatedUser: User): Promise<User | null> => {
    await delay(800);
    const users = DB.getUsers();
    const index = users.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      users[index] = { ...users[index], ...updatedUser };
      DB.saveUsers(users);
      return users[index];
    }
    return null;
  },

  getUsers: async (): Promise<User[]> => {
    await delay(500);
    return DB.getUsers();
  },

  toggleUserStatus: async (userId: string): Promise<string | null> => {
    await delay(400);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user) {
      user.status = user.status === 'Active' ? 'Blocked' : 'Active';
      DB.saveUsers(users);
      return user.status;
    }
    return null;
  },

  // --- BLOOD STOCK API ---
  getBloodStocks: async (): Promise<BloodStock[]> => {
    await delay(600);
    return DB.getStocks();
  },

  // --- REQUESTS API ---
  getDonationRequests: async (): Promise<DonationRequest[]> => {
    await delay(500);
    return DB.getRequests();
  },

  addDonationRequest: async (req: DonationRequest): Promise<void> => {
    await delay(700);
    DB.addRequest(req);
  },

  // --- APPOINTMENTS API ---
  getAppointments: async (): Promise<Appointment[]> => {
    await delay(400);
    return DB.getAppointments();
  },

  scheduleAppointment: async (app: Appointment): Promise<void> => {
    await delay(900);
    DB.saveAppointment(app);
  }
};

