                      <button type="button" onClick={() => setRegisterForm({...registerForm, role: UserRole.USER})} className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${registerForm.role === UserRole.USER ? 'bg-white shadow-sm text-blood-600' : 'text-gray-500'}`}>User</button>
                      <button type="button" onClick={() => setRegisterForm({...registerForm, role: UserRole.DONOR})} className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${registerForm.role === UserRole.DONOR ? 'bg-white shadow-sm text-blood-600' : 'text-gray-500'}`}>Donor</button>
                    </div>
                    <input type="text" placeholder="Full Name" value={registerForm.name} onChange={e => setRegisterForm({...registerForm, name: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-blood-500" required />
                    {registerForm.role === UserRole.DONOR && (
                      <div className="grid grid-cols-2 gap-4">
                         <select value={registerForm.bloodType} onChange={e => setRegisterForm({...registerForm, bloodType: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl outline-none border-none">
                            {['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'].map(t => <option key={t} value={t}>{t}</option>)}
                         </select>
                         <input type="text" placeholder="Location" value={registerForm.location} onChange={e => setRegisterForm({...registerForm, location: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl border-none outline-none"/>
                      </div>
                    )}
                  </>
                )}

                <input type="text" placeholder="Username" value={currentView === 'login' ? loginForm.username : registerForm.username} onChange={e => currentView === 'login' ? setLoginForm({...loginForm, username: e.target.value}) : setRegisterForm({...registerForm, username: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-blood-500" required />
                <input type="password" placeholder="Password" value={currentView === 'login' ? loginForm.password : registerForm.password} onChange={e => currentView === 'login' ? setLoginForm({...loginForm, password: e.target.value}) : setRegisterForm({...registerForm, password: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-blood-500" required />

                {authError && <p className="text-red-500 text-sm font-medium text-center">{authError}</p>}

                <Button isLoading={isAuthLoading} className="w-full py-4 text-lg bg-blood-600 text-white rounded-xl shadow-xl flex gap-2">
                   {currentView === 'login' ? <LogIn size={20}/> : <UserPlus size={20}/>}
                   {currentView === 'login' ? 'Login' : 'Sign Up'}
                </Button>
              </form>
            </div>
          </div>
        )}

        {currentView === 'dashboard' && currentUser && (
          <main className="container mx-auto px-4 py-8 animate-fade-in-up">
            {currentUser.role === UserRole.ADMIN ? <AdminPanel /> : currentUser.role === UserRole.DONOR ? <DonorPanel user={currentUser} /> : <UserPanel />}
          </main>
        )}
      </div>
    </div>
  );
};

export default App;

