type ViewState = 'landing' | 'login' | 'register' | 'dashboard';

const SamratBot: React.FC<{ user: User | null }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ sender: 'user' | 'bot', text: string }[]>([
    { sender: 'bot', text: `Namaste! I'm Samrat. How can I help you today?` }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { sender: 'user', text: userMsg }]);
    setInput('');
    setIsLoading(true);
    const response = await chatWithSamrat(userMsg, user ? `Role: ${user.role}, Name: ${user.name}` : "Guest");
    setMessages(prev => [...prev, { sender: 'bot', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 bg-white rounded-2xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col h-[500px] animate-fade-in-up">
          <div className="bg-blood-600 p-4 text-white flex justify-between items-center">
            <h3 className="font-bold flex items-center gap-2"><div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">🤖</div> Samrat AI</h3>
            <button onClick={() => setIsOpen(false)}><Minus size={18} /></button>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm shadow-sm ${msg.sender === 'user' ? 'bg-blood-600 text-white rounded-tr-none' : 'bg-white border text-gray-800 rounded-tl-none'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && <div className="text-xs text-gray-400 animate-pulse pl-2 flex items-center gap-2"><div className="w-1 h-1 bg-gray-400 rounded-full animate-ping"></div> Samrat is thinking...</div>}
            <div ref={messagesEndRef} />
          </div>
          <div className="p-4 bg-white border-t">
            <div className="relative">
              <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} placeholder="Ask Samrat..." className="w-full pl-4 pr-12 py-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-blood-500 outline-none text-sm"/>
              <button onClick={handleSend} className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 bg-blood-600 text-white rounded-lg hover:scale-110 transition-transform"><Send size={16} /></button>
            </div>
          </div>
        </div>
      )}
      <button onClick={() => setIsOpen(!isOpen)} className="bg-blood-600 text-white p-4 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all group">
        <MessageSquare size={28} className="group-hover:rotate-12 transition-transform" />
      </button>
    </div>
  );
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('landing');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(false);
  const [authError, setAuthError] = useState('');
  const [showSettings, setShowSettings] = useState(false);
  const [notification, setNotification] = useState<string | null>(null);

  // Form States
  const [loginForm, setLoginForm] = useState({ username: '', password: '', role: UserRole.USER });
  const [registerForm, setRegisterForm] = useState({ username: '', name: '', password: '', role: UserRole.USER, bloodType: 'O+', location: '', phone: '', email: '' });

  useEffect(() => {
    const saved = localStorage.getItem('lifeflow_current_user');
    if (saved) {
      setCurrentUser(JSON.parse(saved));
      setCurrentView('dashboard');
    }
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthLoading(true);
    setAuthError('');
    try {
      const user = await API.login(loginForm.username, loginForm.password, loginForm.role);
      if (user) {
        setCurrentUser(user);
        localStorage.setItem('lifeflow_current_user', JSON.stringify(user));
        setCurrentView('dashboard');
        setNotification(`Welcome back, ${user.name}!`);
        setTimeout(() => setNotification(null), 3000);
      } else {
        setAuthError('Invalid credentials or access role.');
      }
    } catch (err) {
      setAuthError('System failure. Database unresponsive.');
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthLoading(true);
    try {
      const user = await API.register(registerForm);
      setCurrentUser(user);
      localStorage.setItem('lifeflow_current_user', JSON.stringify(user));
      setCurrentView('dashboard');
      setNotification("Account created and synced to database.");
      setTimeout(() => setNotification(null), 3000);
    } catch (err) {
      setAuthError("Registration failed. Please try again.");
    }
    setIsAuthLoading(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('lifeflow_current_user');
    setCurrentView('landing');
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900">
      <nav className={`fixed w-full z-40 transition-all duration-500 ${currentView === 'landing' ? 'bg-gray-900/95 border-b border-white/10 py-5' : 'bg-white/90 backdrop-blur-md border-b shadow-sm py-4'}`}>
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setCurrentView(currentUser ? 'dashboard' : 'landing')}>
            <div className="bg-blood-600 text-white p-2.5 rounded-2xl shadow-xl group-hover:scale-110 transition-transform"><Droplet size={26} fill="currentColor"/></div>
            <span className={`text-2xl font-black tracking-tighter ${currentView === 'landing' ? 'text-white' : 'text-gray-900'}`}>LifeFlow</span>
          </div>

          <div className="flex items-center gap-6">
            {!currentUser ? (
              <div className="flex items-center gap-4">
                <div className="group relative">
                  <button className={`font-bold flex items-center gap-2 transition-colors px-4 py-2 rounded-xl hover:bg-white/10 ${currentView === 'landing' ? 'text-white' : 'text-gray-600 hover:bg-gray-100'}`}>
                    <LogIn size={18}/> Access <ChevronDown size={14} className="group-hover:rotate-180 transition-transform"/>
                  </button>
                  <div className="absolute top-full right-0 w-64 bg-white rounded-2xl shadow-2xl p-3 z-50 mt-3 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-300 transform origin-top scale-95 group-hover:scale-100 border border-gray-100">
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-3 mb-2">Select Portal</p>
                    <button onClick={() => { setLoginForm({...loginForm, role: UserRole.ADMIN}); setCurrentView('login'); }} className="w-full text-left p-3 hover:bg-gray-50 rounded-xl text-sm font-bold flex items-center gap-3 transition-colors text-gray-800"><ShieldCheck size={18} className="text-blood-600"/> <div>Admin Console <p className="text-[10px] text-gray-400 font-medium">Control Center</p></div></button>
                    <button onClick={() => { setLoginForm({...loginForm, role: UserRole.DONOR}); setCurrentView('login'); }} className="w-full text-left p-3 hover:bg-gray-50 rounded-xl text-sm font-bold flex items-center gap-3 transition-colors text-gray-800"><Heart size={18} className="text-blood-600"/> <div>Donor Portal <p className="text-[10px] text-gray-400 font-medium">Donate & Earn XP</p></div></button>
                    <button onClick={() => { setLoginForm({...loginForm, role: UserRole.USER}); setCurrentView('login'); }} className="w-full text-left p-3 hover:bg-gray-50 rounded-xl text-sm font-bold flex items-center gap-3 transition-colors text-gray-800"><UserIcon size={18} className="text-blood-600"/> <div>User Panel <p className="text-[10px] text-gray-400 font-medium">Blood Requests</p></div></button>
                  </div>
                </div>
                <Button onClick={() => setCurrentView('register')} className="bg-blood-600 text-white px-8 py-3 rounded-xl font-bold text-sm shadow-xl shadow-blood-500/20 hover:-translate-y-0.5 active:translate-y-0 transition-all">Join Network</Button>
              </div>
            ) : (
