                    <div className="h-px bg-gray-50 my-2 mx-3"></div>
                    <button onClick={handleLogout} className="w-full text-left p-3 hover:bg-red-50 text-red-600 rounded-xl text-sm font-bold flex items-center gap-3 transition-colors"><LogOut size={18}/> Logout Session</button>
                  </div>
