                      <button type="button" onClick={() => setRegisterForm({...registerForm, role: UserRole.USER})} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${registerForm.role === UserRole.USER ? 'bg-white shadow-sm text-blood-600' : 'text-gray-500'}`}>Regular User</button>
