                           </select>
                        </div>
                        <div className="space-y-2">
                           <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">City</p>
                           <input type="text" placeholder="e.g. NY" value={registerForm.location} onChange={e => setRegisterForm({...registerForm, location: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl border border-transparent outline-none focus:ring-2 focus:ring-blood-500 font-bold"/>
