                   <button type="button" onClick={() => setCurrentView(currentView === 'login' ? 'register' : 'login')} className="text-blood-600 font-black ml-1 hover:underline">
                      {currentView === 'login' ? 'Sign up here' : 'Log in here'}
                   </button>
