import { Button } from './components/Button';
import { chatWithSamrat } from './services/geminiService';

type ViewState = 'landing' | 'login' | 'register' | 'dashboard';

const SamratBot: React.FC<{ user: User | null }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ sender: 'user' | 'bot', text: string }[]>([
    { sender: 'bot', text: `Namaste! I'm Samrat. How can I help you today?` }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { sender: 'user', text: userMsg }]);
    setInput('');
    setIsLoading(true);
    const response = await chatWithSamrat(userMsg, user ? `Role: ${user.role}, Name: ${user.name}` : "Guest");
    setMessages(prev => [...prev, { sender: 'bot', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 bg-white rounded-2xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col h-[500px] animate-fade-in-up">
          <div className="bg-blood-600 p-4 text-white flex justify-between items-center">
            <h3 className="font-bold flex items-center gap-2"><div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">🤖</div> Samrat AI</h3>
            <button onClick={() => setIsOpen(false)}><Minus size={18} /></button>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm shadow-sm ${msg.sender === 'user' ? 'bg-blood-600 text-white rounded-tr-none' : 'bg-white border text-gray-800 rounded-tl-none'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && <div className="text-xs text-gray-400 animate-pulse pl-2 flex items-center gap-2"><div className="w-1 h-1 bg-gray-400 rounded-full animate-ping"></div> Samrat is thinking...</div>}
            <div ref={messagesEndRef} />
          </div>
          <div className="p-4 bg-white border-t">
            <div className="relative">
              <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} placeholder="Ask Samrat..." className="w-full pl-4 pr-12 py-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-blood-500 outline-none text-sm"/>
              <button onClick={handleSend} className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 bg-blood-600 text-white rounded-lg hover:scale-110 transition-transform"><Send size={16} /></button>
            </div>
          </div>
        </div>
      )}
      <button onClick={() => setIsOpen(!isOpen)} className="bg-blood-600 text-white p-4 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all group">
        <MessageSquare size={28} className="group-hover:rotate-12 transition-transform" />
      </button>
    </div>
  );
};

const App: React.FC = () => {
