                 className="p-4 rounded-xl bg-gray-50 border-none focus:ring-2 focus:ring-blood-500 outline-none appearance-none font-bold"
              >
                <option value="All">All Types</option>
                <option value="A+">A+</option>
                <option value="O+">O+</option>
                <option value="AB+">AB+</option>
              </select>
              <input 
                 type="text" 
                 placeholder="City or Region" 
                 value={adminSearchCity}
                 onChange={(e) => setAdminSearchCity(e.target.value)}
                 className="flex-1 p-4 rounded-xl bg-gray-50 border-none focus:ring-2 focus:ring-blood-500 outline-none"
              />
              <Button onClick={handleAdminSearch} disabled={isSearching} className="px-8 shadow-xl shadow-blood-500/20">{isSearching ? 'Scanning Network...' : 'Locate Now'}</Button>
          </div>
       </div>

       {isSearching ? (
          <div className="text-center py-12">
             <div className="w-12 h-12 border-4 border-blood-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
             <p className="text-gray-500 font-bold animate-pulse">Accessing secure donor database via Gemini AI...</p>
          </div>
       ) : searchResults.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             {searchResults.map(res => (
               <div key={res.id} className="bg-white p-6 rounded-2xl shadow-sm border-l-4 border-l-blood-600 flex items-start gap-4 hover:shadow-md transition-all">
