                     <td className="py-4">
                       <span className={`px-2 py-1 rounded text-xs font-bold ${req.urgency === 'Critical' ? 'text-red-600 bg-red-50' : req.urgency === 'Medium' ? 'text-orange-600 bg-orange-50' : 'text-green-600 bg-green-50'}`}>
