                     <td className="p-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${user.role === 'DONOR' ? 'bg-red-100 text-red-700' : user.role === 'ADMIN' ? 'bg-gray-800 text-white' : 'bg-blue-100 text-blue-700'}`}>
