type AdminTab = 'dashboard' | 'users' | 'feedback' | 'search';

export const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('dashboard');

  // Data States
  const [users, setUsers] = useState<User[]>([]);
  const [requests, setRequests] = useState<DonationRequest[]>([]);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);
  const [stocks, setStocks] = useState<BloodStock[]>([]);
  const [logs, setLogs] = useState<SecurityLog[]>([]);
  const [generatedKey, setGeneratedKey] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [adminSearchCity, setAdminSearchCity] = useState('');
  const [adminSearchType, setAdminSearchType] = useState('All');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  // Reply State
  const [replyingTo, setReplyingTo] = useState<Feedback | null>(null);
  const [replyText, setReplyText] = useState('');
  const [isSubmittingReply, setIsSubmittingReply] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = async () => {
    if (users.length === 0) setIsLoading(true);
    try {
      const [u, r, f, s, l] = await Promise.all([
        API.getUsers(),
        API.getDonationRequests(),
        API.getFeedbacks(),
        API.getBloodStocks(),
        API.getSecurityLogs()
      ]);
      setUsers(u);
      setRequests(r);
      setFeedbacks(f);
      setStocks(s);
      setLogs(l);
    } finally {
      setIsLoading(false);
    }
  };

  const generateKey = () => {
    setGeneratedKey(`BLOOD-KEY-${Math.floor(1000 + Math.random() * 9000)}`);
  };

  const handleBlockUser = async (id: string, name: string) => {
    if (confirm(`Are you sure you want to toggle BLOCK status for ${name}?`)) {
      await API.toggleUserStatus(id);
      refreshData();
      alert(`Status updated for ${name}`);
    }
  };

  const handlePromoteUser = async (id: string, name: string) => {
    const newLevel = await API.promoteDonor(id);
    if (newLevel) {
      refreshData();
      alert(`${name} promoted to Level ${newLevel}!`);
    }
  };

  const handleIssueKey = async (id: string, name: string) => {
    const key = await API.issueEmergencyKey(id);
    alert(`Emergency Key Issued to ${name}: ${key}`);
  };

  const handleAdminSearch = async () => {
    setIsSearching(true);
    setSearchResults([]);
    try {
       const results = await findDonorsWithAI(adminSearchType, adminSearchCity);
       setSearchResults(results);
    } catch (e) {
       console.error(e);
    } finally {
       setIsSearching(false);
    }
  };

  const handleReplySubmit = async () => {
    if (!replyingTo || !replyText.trim()) return;
    setIsSubmittingReply(true);
    try {
      await API.replyToFeedback(replyingTo.id, replyText);
      setReplyText('');
      setReplyingTo(null);
      await refreshData();
    } finally {
      setIsSubmittingReply(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 space-y-4">
        <Loader2 className="animate-spin text-blood-600" size={48} />
        <p className="text-gray-500 font-bold tracking-tight">Syncing with Secure Admin Database...</p>
      </div>
    );
  }

  // --- Sub-Components ---

  const renderDashboard = () => (
    <div className="space-y-8 animate-fade-in-up">
