                              {['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'].map(t => <option key={t} value={t}>{t}</option>)}
                           </select>
                        </div>
                        <div className="space-y-2">
                           <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">City</p>
                           <input type="text" placeholder="e.g. NY" value={registerForm.location} onChange={e => setRegisterForm({...registerForm, location: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl border border-transparent outline-none focus:ring-2 focus:ring-blood-500 font-bold"/>
                        </div>
                      </div>
                    )}
                  </>
                )}

                <div className="space-y-2">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Username</p>
                   <input type="text" placeholder="Unique identifier" value={currentView === 'login' ? loginForm.username : registerForm.username} onChange={e => currentView === 'login' ? setLoginForm({...loginForm, username: e.target.value}) : setRegisterForm({...registerForm, username: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-blood-500 border border-transparent transition-all" required />
                </div>
                <div className="space-y-2">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Password</p>
                   <input type="password" placeholder="••••••••" value={currentView === 'login' ? loginForm.password : registerForm.password} onChange={e => currentView === 'login' ? setLoginForm({...loginForm, password: e.target.value}) : setRegisterForm({...registerForm, password: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-blood-500 border border-transparent transition-all" required />
                </div>

                {authError && <div className="p-4 bg-red-50 text-red-600 text-xs font-bold rounded-xl text-center flex items-center justify-center gap-2"><AlertTriangle size={14}/> {authError}</div>}

                <Button isLoading={isAuthLoading} className="w-full py-5 text-lg bg-blood-600 text-white rounded-2xl shadow-2xl shadow-blood-500/30 flex gap-3 hover:-translate-y-1 active:translate-y-0 transition-all font-black">
                   {currentView === 'login' ? <LogIn size={22}/> : <UserPlus size={22}/>}
                   {currentView === 'login' ? 'Login' : 'Sign Up'}
                </Button>

                <p className="text-center text-xs text-gray-400 font-medium">
                   {currentView === 'login' ? "Don't have an account?" : "Already a member?"} 
                   <button type="button" onClick={() => setCurrentView(currentView === 'login' ? 'register' : 'login')} className="text-blood-600 font-black ml-1 hover:underline">
                      {currentView === 'login' ? 'Sign up here' : 'Log in here'}
                   </button>
                </p>
              </form>
            </div>
          </div>
        )}

        {currentView === 'dashboard' && currentUser && (
          <main className="container mx-auto px-6 py-12 animate-fade-in-up">
            {currentUser.role === UserRole.ADMIN ? <AdminPanel /> : currentUser.role === UserRole.DONOR ? <DonorPanel user={currentUser} /> : <UserPanel />}
          </main>
        )}
      </div>
    </div>
  );
};

export default App;

