                   <Award size={120} />
                </div>
                <div className="w-20 h-20 bg-blood-600 rounded-3xl flex items-center justify-center text-white font-black text-3xl shadow-xl shadow-blood-500/30">
                   {currentLevel}
                </div>
                <div className="flex-1 w-full text-center md:text-left">
                   <h3 className="text-xl font-bold text-gray-900 mb-2">Rank: Level {currentLevel} Elite Donor</h3>
                   <div className="w-full bg-gray-200 h-3 rounded-full overflow-hidden mb-2">
