                <Button onClick={simulateDonationXp} className="text-xs px-6 rounded-2xl whitespace-nowrap bg-gray-900 hover:bg-black">Boost XP (Simulate)</Button>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
