                        <div className="flex gap-3 w-full sm:w-auto">
                           <button className="flex-1 sm:flex-none px-8 py-2 rounded-xl bg-white border border-gray-200 text-xs font-black uppercase tracking-widest hover:bg-blood-50 hover:text-blood-600 hover:border-blood-200 transition-all">Yes</button>
                           <button className="flex-1 sm:flex-none px-8 py-2 rounded-xl bg-white border border-gray-200 text-xs font-black uppercase tracking-widest hover:bg-green-50 hover:text-green-600 hover:border-green-200 transition-all shadow-sm">No</button>
