                <Button className="w-full py-5 text-xl font-black rounded-3xl shadow-2xl shadow-blood-500/20 tracking-widest" onClick={() => {setCurrentXp(prev => prev + 5); alert('Profile Synced! +5 XP Earned.');}}>SYNC MEDICAL PROFILE</Button>
