           <div className="p-8 space-y-8">
              <div className="bg-blue-50 p-6 rounded-[2rem] border border-blue-100">
                 <p className="text-[10px] text-gray-400 uppercase font-black tracking-[0.2em] mb-1">Target Facility</p>
                 <p className="text-xl font-black text-blue-900 mb-1">{bookingRequest.requesterName}</p>
                 <p className="text-sm text-blue-700 font-medium flex items-center gap-2"><MapPin size={14}/> {bookingRequest.location}</p>
              </div>

              <div className="space-y-3">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Preferred Date</label>
                 <input 
                   type="date" 
                   value={bookingDate} 
                   onChange={(e) => setBookingDate(e.target.value)}
                   className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-blood-500 outline-none font-bold text-lg"
                 />
              </div>

              <div className="space-y-4">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Clinical Slots</label>
                 <div className="grid grid-cols-2 gap-3">
                   {['09:00 AM', '11:00 AM', '02:00 PM', '04:00 PM'].map(time => (
                     <button 
                       key={time} 
                       onClick={() => setBookingTime(time)}
                       className={`px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all border-2 ${bookingTime === time ? 'bg-blood-600 text-white border-blood-600 shadow-xl scale-[1.02]' : 'bg-white text-gray-600 border-gray-100 hover:bg-gray-50'}`}
                     >
                       {time}
                     </button>
                   ))}
                 </div>
              </div>

              <Button onClick={confirmBooking} disabled={!bookingDate || !bookingTime} className="w-full py-5 text-lg font-black rounded-[1.5rem] tracking-[0.2em] shadow-2xl shadow-blood-500/20 uppercase">Lock Slot</Button>
           </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 pb-12">
      <div className="bg-white p-2.5 rounded-3xl shadow-sm border border-gray-100 inline-flex flex-wrap gap-2 w-full lg:w-auto">
         <button onClick={() => setActiveTab('dashboard')} className={`px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'dashboard' ? 'bg-gray-900 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Command Center</button>
         <button onClick={() => setActiveTab('requests')} className={`px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'requests' ? 'bg-blood-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Live Demand</button>
         <button onClick={() => setActiveTab('emergency')} className={`px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'emergency' ? 'bg-red-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Priority Access</button>
         <button onClick={() => setActiveTab('certificates')} className={`px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'certificates' ? 'bg-blue-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Vault</button>
         <button onClick={() => setActiveTab('registration')} className={`px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'registration' ? 'bg-green-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Profile System</button>
