  );
};

import React, { useState, useEffect } from 'react';
import { Heart, Calendar, CheckCircle, Lock, MapPin, Award, Clock, CreditCard, Share2, FileText, Upload, Eye, Activity, Trophy, Building2, User as UserIcon, ArrowRight, AlertCircle, Search, Phone, MessageCircle, X, Key, Sparkles, TrendingUp, Droplet } from 'lucide-react';
import { User, Achievement, Appointment, BloodRequest, DonorCertificate, EmergencyKey } from '../types';
import { MockBackend } from '../services/mockBackend';
import { Button } from './Button';
import { getHealthTip, findDonorsWithAI } from '../services/geminiService';

interface DonorPanelProps {
  user: User;
}

type ActiveTab = 'dashboard' | 'requests' | 'certificates' | 'registration' | 'emergency';

export const DonorPanel: React.FC<DonorPanelProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<ActiveTab>('dashboard');

  // Data States
  const [specialKey, setSpecialKey] = useState('');
  const [isVerified, setIsVerified] = useState(user.isVerified);
  const [healthTip, setHealthTip] = useState('');
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [bloodRequests, setBloodRequests] = useState<BloodRequest[]>([]);
  const [certificates, setCertificates] = useState<DonorCertificate[]>([]);
  const [emergencyKeys, setEmergencyKeys] = useState<EmergencyKey[]>([]);

  // Dynamic XP State
  const [currentXp, setCurrentXp] = useState(user.xp || 0);
  const [currentLevel, setCurrentLevel] = useState(user.level || 1);

  // Emergency Search State
  const [searchBloodType, setSearchBloodType] = useState('All');
  const [searchCity, setSearchCity] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [emergencySearchResults, setEmergencySearchResults] = useState<User[]>([]);

  // Booking Modal State
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingRequest, setBookingRequest] = useState<BloodRequest | null>(null);
  const [bookingDate, setBookingDate] = useState('');
  const [bookingTime, setBookingTime] = useState('');

  // Calculations
  const xpInCurrentLevel = currentXp % 100;
  const progress = (xpInCurrentLevel / 100) * 100;

  useEffect(() => {
    const loadData = async () => {
      setHealthTip(await getHealthTip('Donor'));
      setAchievements(MockBackend.getAchievements());
      setAppointments(MockBackend.getAppointments());
      setBloodRequests(MockBackend.getBloodRequestsFeed());
      setCertificates(MockBackend.getMyCertificates(user.id));
      setEmergencyKeys(MockBackend.getEmergencyKeys());
    };
    loadData();
  }, [user.id]);

  const handleVerify = () => {
    if (MockBackend.verifyDonorKey(specialKey)) {
      setIsVerified(true);
      alert("Verified successfully!");
    } else {
      alert("Invalid Key");
    }
  };

  const simulateDonationXp = () => {
    const earned = 25;
    const newXp = currentXp + earned;
    setCurrentXp(newXp);

    // Check for level up
    const newLevel = Math.floor(newXp / 100) + 1;
    if (newLevel > currentLevel) {
      setCurrentLevel(newLevel);
      alert(`🎉 LEVEL UP! You are now Level ${newLevel}!`);
    } else {
      alert(`Donation Complete! You earned ${earned} XP!`);
    }
  };

  const openBookingModal = (request: BloodRequest) => {
    setBookingRequest(request);
    setBookingDate(new Date().toISOString().split('T')[0]); // Default today
    setShowBookingModal(true);
  };

  const confirmBooking = () => {
    if (!bookingRequest || !bookingDate || !bookingTime) return;

    const newApp: Appointment = {
      id: Date.now().toString(),
      hospitalName: bookingRequest.requesterName,
      date: bookingDate,
      time: bookingTime,
      status: 'Scheduled'
    };
    MockBackend.scheduleAppointment(newApp);
    setAppointments([...appointments, newApp]);

    // Earn some small XP for scheduling
    setCurrentXp(prev => prev + 5);

    alert(`Donation scheduled for ${bookingRequest.requesterName} on ${bookingDate} at ${bookingTime}. +5 XP Earned!`);
    setShowBookingModal(false);
    setBookingRequest(null);
    setBookingTime('');
  };

  const handleEmergencySearch = async () => {
    setIsSearching(true);
    setEmergencySearchResults([]);
    await new Promise(resolve => setTimeout(resolve, 2000));
    try {
      const results = await findDonorsWithAI(searchBloodType, searchCity);
      setEmergencySearchResults(results);
    } catch (error) {
      console.error("Search failed", error);
      setEmergencySearchResults(MockBackend.searchDonors(searchBloodType, searchCity));
    } finally {
      setIsSearching(false);
    }
  };

  const handleFileUpload = () => {
    setTimeout(() => {
      const newCert: DonorCertificate = {
        id: Date.now().toString(),
        donorId: user.id,
        date: new Date().toISOString().split('T')[0],
        hospitalName: 'Community Upload',
        imageUrl: 'placeholder'
      };
      MockBackend.addCertificate(newCert);
      setCertificates([...certificates, newCert]);
      setCurrentXp(prev => prev + 10);
      alert("Certificate Uploaded! +10 XP Earned.");
    }, 1000);
  };

  const showFakeAlert = (msg: string) => alert(`Mock Data: ${msg}`);

  // --- Render Sections ---

  const LevelProgressCard = () => (
    <div className="bg-gradient-to-br from-gray-900 via-gray-800 to-blood-900 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden group">
      <div className="absolute top-0 right-0 -mt-10 -mr-10 w-80 h-80 bg-blood-600 rounded-full blur-[100px] opacity-20 group-hover:opacity-30 transition-opacity duration-700"></div>
      <div className="absolute bottom-0 left-0 -mb-10 -ml-10 w-40 h-40 bg-orange-600 rounded-full blur-[80px] opacity-10"></div>

      <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-8">
        <div className="flex items-center gap-6">
          <div className="relative">
            <div className="w-24 h-24 rounded-full bg-white/10 flex items-center justify-center border-4 border-blood-500 shadow-[0_0_25px_rgba(225,29,72,0.4)] animate-pulse">
              <span className="text-4xl font-black text-white">{currentLevel}</span>
            </div>
            <div className="absolute -bottom-2 -right-2 bg-blood-600 p-1.5 rounded-full border-2 border-gray-900">
              <Trophy size={16} className="text-yellow-400" />
            </div>
          </div>
          <div>
            <p className="text-blood-400 text-xs font-black uppercase tracking-[0.2em] mb-1">Donor Excellence</p>
            <h2 className="text-3xl font-bold text-white mb-1">Elite Lifesaver</h2>
            <div className="flex items-center gap-2 text-sm text-gray-400">
              <Sparkles size={14} className="text-yellow-500" />
              <span>{currentXp} Total XP</span>
              <span className="text-gray-600">•</span>
              <span className="text-green-400 font-bold">Level {currentLevel}</span>
            </div>
          </div>
        </div>

        <div className="w-full md:w-5/12 space-y-4">
          <div className="flex justify-between items-end mb-1">
            <span className="text-xs font-bold uppercase text-gray-400 tracking-wider">Next Level Progress</span>
            <span className="text-xl font-black text-blood-400">{Math.floor(progress)}%</span>
          </div>
          <div className="w-full bg-white/5 rounded-full h-5 p-1 border border-white/10 relative">
            <div 
              className="bg-gradient-to-r from-blood-600 via-blood-500 to-orange-500 h-full rounded-full transition-all duration-700 ease-out shadow-[0_0_15px_rgba(225,29,72,0.3)]" 
              style={{ width: `${progress}%` }}
            >
              <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/wave.png')] opacity-20"></div>
            </div>
          </div>
          <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-500">
            <span>Level {currentLevel}</span>
            <span>{xpInCurrentLevel} / 100 XP TO LEVEL {currentLevel + 1}</span>
          </div>
        </div>

        <div className="hidden lg:block">
           <Button onClick={simulateDonationXp} variant="outline" className="border-white/20 text-white hover:bg-white/10 gap-2 rounded-2xl py-3 px-6">
             <TrendingUp size={18} /> Simulate XP
           </Button>
        </div>
      </div>
    </div>
  );

  const renderDashboard = () => (
    <div className="space-y-8 animate-fade-in-up">
       <LevelProgressCard />

       <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
         <div className="space-y-8">
            <div className="relative h-56 rounded-[2rem] overflow-hidden shadow-2xl transition-transform hover:scale-[1.02] duration-500 group cursor-pointer border border-white/10">
               <div className="absolute inset-0 bg-gradient-to-br from-blood-600 to-blood-900 group-hover:from-blood-700 group-hover:to-blood-950 transition-all duration-500"></div>
               <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
               <div className="relative z-10 p-8 flex flex-col justify-between h-full text-white">
                 <div className="flex justify-between items-start">
                   <div>
                     <p className="text-[10px] uppercase font-black tracking-[0.3em] opacity-60 mb-1">Official Member ID</p>
                     <h3 className="font-bold text-xl tracking-wider flex items-center gap-2 font-mono">{user.id.toUpperCase()}</h3>
                   </div>
                   {isVerified ? (
                     <div className="bg-green-500/20 p-2 rounded-xl backdrop-blur-md border border-green-500/30">
                       <CheckCircle className="text-green-400" size={24} />
                     </div>
                   ) : (
                     <div className="bg-white/10 p-2 rounded-xl backdrop-blur-md border border-white/20">
                       <Lock className="text-white/50" size={24} />
                     </div>
                   )}
                 </div>
                 <div className="flex items-end gap-6">
                   <div className="bg-white/10 backdrop-blur-xl rounded-2xl p-4 text-center min-w-[80px] border border-white/20 shadow-xl">
                     <p className="text-[10px] opacity-60 uppercase font-black mb-1">Group</p>
                     <p className="text-3xl font-black">{user.bloodType || 'N/A'}</p>
                   </div>
                   <div className="flex-1 pb-1">
                     <p className="text-lg font-bold opacity-90 leading-tight">{user.name}</p>
                     <p className="text-[10px] opacity-50 uppercase font-black tracking-widest mt-1">Verified Donor Since {user.joinDate || '2023'}</p>
                   </div>
                 </div>
               </div>
            </div>

