  saveFeedbacks: (feedbacks: Feedback[]) => localStorage.setItem(DB_KEYS.FEEDBACKS, JSON.stringify(feedbacks)),

  getLogs: (): SecurityLog[] => JSON.parse(localStorage.getItem(DB_KEYS.LOGS) || '[]'),

  addLog: (log: SecurityLog) => {
