import { User, UserRole, BloodStock, DonationRequest, Appointment, Feedback, SecurityLog } from "../types";
import { DB } from "./db";

const delay = (ms: number = 600) => new Promise(resolve => setTimeout(resolve, ms));

export const API = {
  // --- AUTH ---
  login: async (username: string, password: string, role: UserRole): Promise<User | null> => {
    await delay(800);
    const users = DB.getUsers();

    // Strict matching in mock DB
    const user = users.find(u => 
      u.username.toLowerCase() === username.toLowerCase() && 
      (u as any).password === password &&
      u.role === role
    );

    if (user) {
      DB.addLog({ 
        id: `log-${Date.now()}`, 
        severity: 'Low', 
        message: `${role} Login Successful: ${user.username}`, 
        timestamp: new Date().toISOString() 
      });
      return user;
    }

    return null;
  },

  register: async (userData: Partial<User & { password?: string }>): Promise<User> => {
    await delay(1000);
    const users = DB.getUsers();

    // Check for existing username
    if (users.some(u => u.username.toLowerCase() === userData.username?.toLowerCase())) {
      throw new Error("Username already taken.");
    }

    const newUser: User = {
      id: `u-${Date.now()}`,
      username: userData.username || '',
      // name is defaulted to username since Full Name was removed from UI
      name: userData.username || '',
      role: userData.role || UserRole.USER,
      bloodType: userData.bloodType,
      location: userData.location,
      phone: userData.phone,
      email: userData.email,
      address: userData.address,
      joinDate: new Date().toISOString().split('T')[0],
      status: 'Active',
      level: 1,
      xp: 0
    };

    // Explicitly store password in the database object for login verification
    (newUser as any).password = userData.password;

    users.push(newUser);
    DB.saveUsers(users);

    DB.addLog({ 
      id: `log-${Date.now()}`, 
      severity: 'Low', 
      message: `New User Registered: ${newUser.username} as ${newUser.role}`, 
      timestamp: new Date().toISOString() 
    });

    return newUser;
  },

  // --- USERS ---
  getUsers: async (): Promise<User[]> => {
    await delay(300);
    return DB.getUsers();
  },

  updateUser: async (updatedUser: User): Promise<User | null> => {
    await delay(500);
    const users = DB.getUsers();
    const index = users.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      users[index] = { ...users[index], ...updatedUser };
      DB.saveUsers(users);
      return users[index];
    }
    return null;
  },

  toggleUserStatus: async (userId: string): Promise<string | null> => {
    await delay(400);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user) {
      user.status = user.status === 'Active' ? 'Blocked' : 'Active';
      DB.saveUsers(users);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Medium', message: `User status changed: ${user.name} (${user.status})`, timestamp: new Date().toISOString() });
      return user.status;
    }
    return null;
  },

  promoteDonor: async (userId: string): Promise<number | null> => {
    await delay(500);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user && user.role === UserRole.DONOR) {
      user.level = (user.level || 1) + 1;
      user.xp = (user.xp || 0) + 100;
      DB.saveUsers(users);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Low', message: `Donor Promoted: ${user.name} to Level ${user.level}`, timestamp: new Date().toISOString() });
      return user.level;
    }
    return null;
  },

  // --- BLOOD STOCK ---
  getBloodStocks: async (): Promise<BloodStock[]> => {
    await delay(400);
    return DB.getStocks();
  },

  // --- REQUESTS ---
  getDonationRequests: async (): Promise<DonationRequest[]> => {
    await delay(300);
    return DB.getRequests();
  },

  addDonationRequest: async (req: DonationRequest): Promise<void> => {
    await delay(500);
    DB.addRequest(req);
  },

  // --- APPOINTMENTS ---
  getAppointments: async (): Promise<Appointment[]> => {
    await delay(200);
    return DB.getAppointments();
  },

  scheduleAppointment: async (app: Appointment): Promise<void> => {
    await delay(600);
    DB.saveAppointment(app);
  },

  // --- ADMIN SPECIALS ---
  getFeedbacks: async (): Promise<Feedback[]> => {
    await delay(200);
    return DB.getFeedbacks();
  },

  replyToFeedback: async (feedbackId: string, reply: string): Promise<void> => {
    await delay(400);
    const feedbacks = DB.getFeedbacks();
    const index = feedbacks.findIndex(f => f.id === feedbackId);
    if (index !== -1) {
      feedbacks[index].reply = reply;
      DB.saveFeedbacks(feedbacks);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Low', message: `Admin replied to feedback ${feedbackId}`, timestamp: new Date().toISOString() });
    }
  },

  getSecurityLogs: async (): Promise<SecurityLog[]> => {
    await delay(200);
    return DB.getLogs();
  },

  issueEmergencyKey: async (userId: string): Promise<string> => {
    await delay(500);
    const code = `GRANT-${Math.floor(1000 + Math.random() * 8999)}`;
    DB.addLog({ id: `log-${Date.now()}`, severity: 'High', message: `Emergency Key Issued to ${userId}: ${code}`, timestamp: new Date().toISOString() });
    return code;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Droplet, LogOut, Menu, X, ArrowLeft, User as UserIcon, MessageSquare, 
  Send, Minus, Bell, ChevronDown, Heart, Activity, Phone, ShieldCheck, 
  Mail, MapPin, Save, Settings, Loader2, UserPlus, LogIn, Database, 
  CheckCircle, AlertTriangle, Mic, Camera, BrainCircuit, Headphones
} from 'lucide-react';
import { User, UserRole } from './types';
import { API } from './services/api';
import { AdminPanel } from './components/AdminPanel';
import { DonorPanel } from './components/DonorPanel';
import { UserPanel } from './components/UserPanel';
import { LandingPage } from './components/LandingPage';
import { Button } from './components/Button';
import { chatWithSamrat, analyzeMedicalImage, transcribeAudio } from './services/geminiService';

type ViewState = 'landing' | 'login' | 'register' | 'dashboard';

const SamratBot: React.FC<{ user: User | null }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ sender: 'user' | 'bot', text: string, type?: 'image' | 'audio' }[]>([
    { sender: 'bot', text: `Namaste! I'm Samrat. How can I help you today?` }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLiveActive, setIsLiveActive] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isOpen]);

  const handleSend = async (overrideMsg?: string) => {
    const userMsg = overrideMsg || input;
    if (!userMsg.trim()) return;

    setMessages(prev => [...prev, { sender: 'user', text: userMsg }]);
    if (!overrideMsg) setInput('');
    setIsLoading(true);

    const context = user ? `Role: ${user.role}, Name: ${user.name}` : "Guest";
    const response = await chatWithSamrat(userMsg, context, isThinking);

    setMessages(prev => [...prev, { sender: 'bot', text: response }]);
    setIsLoading(false);
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64Data = (event.target?.result as string).split(',')[1];
      setMessages(prev => [...prev, { sender: 'user', text: "Uploaded an image for analysis...", type: 'image' }]);
      setIsLoading(true);

      const analysis = await analyzeMedicalImage(base64Data, file.type);
      setMessages(prev => [...prev, { sender: 'bot', text: analysis }]);
      setIsLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        const reader = new FileReader();
        reader.onload = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsLoading(true);
          const transcript = await transcribeAudio(base64Audio);
          if (transcript) {
            setInput(transcript);
            handleSend(transcript);
          }
          setIsLoading(false);
        };
        reader.readAsDataURL(audioBlob);
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Mic access failed", err);
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  const toggleLiveVoice = async () => {
    setIsLiveActive(!isLiveActive);
    if (!isLiveActive) {
      setMessages(prev => [...prev, { sender: 'bot', text: "Voice session active. I'm listening..." }]);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 bg-white rounded-2xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col h-[550px] animate-fade-in-up">
          <div className="bg-blood-600 p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">🤖</div>
              <div>
                <h3 className="font-bold">Samrat AI</h3>
                <p className="text-[10px] opacity-70">Powered by Gemini 3 Pro</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button 
                onClick={() => setIsThinking(!isThinking)} 
                className={`p-1.5 rounded-lg transition-colors ${isThinking ? 'bg-white text-blood-600' : 'hover:bg-white/20'}`}
                title="Thinking Mode (Deep Reasoning)"
              >
                <BrainCircuit size={18} />
              </button>
              <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-1.5 rounded-lg"><Minus size={18} /></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm ${
                  msg.sender === 'user' 
                    ? 'bg-blood-600 text-white rounded-tr-none' 
                    : 'bg-white border text-gray-800 rounded-tl-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex items-center gap-2 pl-2">
                <Loader2 size={14} className="animate-spin text-blood-600" />
                <p className="text-xs text-gray-400 font-medium">{isThinking ? 'Processing complex query...' : 'Thinking...'}</p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-4 bg-white border-t space-y-3">
            <div className="flex items-center gap-2">
              <input 
                value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyPress={e => e.key === 'Enter' && handleSend()} 
                placeholder="Ask Samrat..." 
                className="flex-1 pl-4 pr-4 py-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-blood-500 outline-none text-sm"
              />
              <button 
                onClick={() => handleSend()} 
                className="p-3 bg-blood-600 text-white rounded-xl hover:scale-105 active:scale-95 transition-all shadow-md"
              >
                <Send size={18} />
              </button>
            </div>

            <div className="flex justify-between items-center px-1">
              <div className="flex gap-2">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="p-2 text-gray-500 hover:text-blood-600 hover:bg-blood-50 rounded-lg transition-all"
                  title="Analyze Image"
                >
                  <Camera size={20} />
                </button>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />

                <button 
                  onMouseDown={startRecording}
                  onMouseUp={stopRecording}
                  onMouseLeave={isRecording ? stopRecording : undefined}
                  className={`p-2 rounded-lg transition-all ${isRecording ? 'text-blood-600 bg-blood-50 animate-pulse' : 'text-gray-500 hover:text-blood-600 hover:bg-blood-50'}`}
                  title="Push to Transcribe"
                >
                  <Mic size={20} />
                </button>
              </div>

              <button 
                onClick={toggleLiveVoice}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-all ${
                  isLiveActive ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
                }`}
              >
                <Headphones size={14} />
                {isLiveActive ? 'Live Active' : 'Voice Mode'}
              </button>
            </div>
          </div>
        </div>
      )}
      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className="bg-blood-600 text-white p-4 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all group relative"
      >
        <MessageSquare size={28} className="group-hover:rotate-12 transition-transform" />
        {isLiveActive && <span className="absolute top-0 right-0 w-3 h-3 bg-green-500 border-2 border-white rounded-full"></span>}
      </button>
    </div>
  );
};

