                className="text-[10px] gap-2 font-black uppercase tracking-widest rounded-xl border-gray-100 h-auto py-2 px-4" 
                onClick={() => setShowAllStocks(!showAllStocks)}
             >
               {showAllStocks ? 'Compact View' : 'Full Index'} {showAllStocks ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
             </Button>
           </div>

           <div className="space-y-8 max-h-[350px] overflow-y-auto pr-4 custom-scrollbar">
              {displayedStocks.map(stock => (
                <div key={stock.id} className="group cursor-pointer hover:bg-gray-50/80 p-4 rounded-2xl transition-all border border-transparent hover:border-gray-100" onClick={() => showFakeAlert(`Clinic Info: ${stock.hospitalName}`)}>
                  <div className="flex justify-between text-sm font-black mb-3 items-end">
                    <span className="flex items-center gap-4">
                      <span className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xs font-black shadow-inner group-hover:bg-blood-600 group-hover:text-white transition-colors">{stock.bloodType}</span>
                      <div className="text-left">
                        <p className="text-gray-900 leading-tight">{stock.hospitalName}</p>
                        <p className="text-[10px] text-gray-400 uppercase tracking-widest">{stock.city}</p>
                      </div>
                    </span>
                    <span className={`text-sm tracking-tighter ${stock.units < 10 ? 'text-red-600' : 'text-green-600'}`}>{stock.units} UNITS REMAINING</span>
                  </div>
                  <div className="w-full h-4 bg-gray-100 rounded-full overflow-hidden shadow-inner p-1">
                    <div 
                      className={`h-full rounded-full relative overflow-hidden transition-all duration-1000 ease-out ${stock.units < 10 ? 'bg-gradient-to-r from-red-600 to-red-400 shadow-[0_0_15px_rgba(220,38,38,0.3)]' : 'bg-gradient-to-r from-green-600 to-green-400 shadow-[0_0_15px_rgba(22,163,74,0.3)]'}`}
                      style={{ width: `${Math.min((stock.units / stock.maxCapacity) * 100, 100)}%` }}
                    >
                       <div className="absolute inset-0 bg-white/20 w-full h-full animate-[shimmer_2s_infinite]"></div>
                    </div>
                  </div>
                </div>
              ))}
              {displayedStocks.length === 0 && <p className="text-center py-20 text-gray-400 font-bold uppercase tracking-widest">Scanning network for live stock...</p>}
           </div>
        </div>
      </div>

      {/* Search & Results */}
      <div className="bg-white rounded-[3rem] shadow-2xl border border-gray-100 overflow-hidden">
        <div className="p-10 border-b border-gray-100 bg-gray-50/50">
           <h2 className="text-3xl font-black tracking-tighter mb-8">SOURCE DONOR NETWORK</h2>
           <div className="flex flex-col md:flex-row gap-6">
              <div className="flex-1 relative">
                 <Droplet className="absolute left-6 top-1/2 -translate-y-1/2 text-blood-600" size={24}/>
                 <select 
                    value={bloodType} 
                    onChange={(e) => setBloodType(e.target.value)}
                    className="w-full pl-16 pr-8 py-5 rounded-2xl border-none bg-white shadow-xl focus:ring-2 focus:ring-blood-500 appearance-none font-bold text-lg"
                  >
                    <option value="All">All Blood Assets</option>
                    <option value="A+">A+ Assets</option>
                    <option value="A-">A- Assets</option>
                    <option value="O+">O+ Assets</option>
                    <option value="O-">O- Assets</option>
                    <option value="B+">B+ Assets</option>
                    <option value="B-">B- Assets</option>
                    <option value="AB+">AB+ Assets</option>
                    <option value="AB-">AB- Assets</option>
                  </select>
              </div>
              <div className="flex-[2] relative">
                 <MapPin className="absolute left-6 top-1/2 -translate-y-1/2 text-blood-600" size={24}/>
                 <input 
                  type="text" 
                  placeholder="Identify Target City (e.g., London)..." 
                  value={city}
                  onChange={(e) => setCity(e.target.value)}
                  className="w-full pl-16 pr-8 py-5 rounded-2xl border-none bg-white shadow-xl focus:ring-2 focus:ring-blood-500 font-bold text-lg"
                 />
              </div>
              <Button 
                onClick={handleSearch} 
                disabled={isSearching}
                className="px-12 py-5 rounded-2xl shadow-2xl shadow-blood-500/30 text-lg font-black tracking-widest uppercase"
              >
                {isSearching ? 'SCANNING...' : 'SCAN NETWORK'}
              </Button>
           </div>
        </div>

        <div className="p-10 bg-gray-50 min-h-[400px]">
           {isSearching ? (
              <div className="flex flex-col items-center justify-center h-[300px] space-y-6">
                <div className="w-16 h-16 border-4 border-blood-200 border-t-blood-600 rounded-full animate-spin"></div>
                <p className="text-gray-400 font-black tracking-[0.3em] animate-pulse uppercase">DECRYPTING DONOR PROFILES...</p>
              </div>
           ) : searchResults.length > 0 ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
               {searchResults.map(donor => (
                 <div key={donor.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm hover:shadow-2xl transition-all border border-gray-100 group relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                      <Droplet size={80} />
                    </div>
                    <div className="flex items-center gap-6 mb-8">
