                           <p className="text-sm font-black text-green-600 flex items-center gap-2"><Phone size={14} /> {donor.phone}</p>
                         )}
                       </div>
                    </div>
                    <div className="flex gap-3">
                      <Button className="flex-[2] py-4 text-xs font-black uppercase tracking-widest rounded-xl bg-blood-600 shadow-xl shadow-blood-500/10" onClick={() => showFakeAlert(`Request sent to ${donor.name}`)}>Send Request</Button>
                      <Button variant="secondary" className="flex-1 py-4 rounded-xl flex items-center justify-center bg-gray-100 hover:bg-gray-200" onClick={() => showFakeAlert(`Opening chat with ${donor.name}`)}><MessageCircle size={22}/></Button>
                    </div>
