          <Button onClick={() => setShowFeedbackModal(true)} className="px-12 py-6 text-xl !bg-white !text-gray-900 rounded-3xl font-black shadow-2xl hover:scale-105 active:scale-95 transition-all uppercase tracking-widest">Submit Feedback</Button>
        </div>
      </div>

      {/* Feedback Modal */}
      {showFeedbackModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[70] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-md shadow-2xl border border-white/10 overflow-hidden animate-fade-in-up">
            <div className="bg-gray-900 p-8 flex justify-between items-center text-white">
