import { MockBackend } from '../services/mockBackend';
import { Button } from './Button';
import { getHealthTip, findDonorsWithAI } from '../services/geminiService';

interface DonorPanelProps {
  user: User;
}

type ActiveTab = 'dashboard' | 'requests' | 'certificates' | 'registration' | 'emergency' | 'feedback';

export const DonorPanel: React.FC<DonorPanelProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<ActiveTab>('dashboard');

  // Data States
  const [specialKey, setSpecialKey] = useState('');
  const [isVerified, setIsVerified] = useState(user.isVerified);
  const [healthTip, setHealthTip] = useState('');
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [bloodRequests, setBloodRequests] = useState<BloodRequest[]>([]);
  const [certificates, setCertificates] = useState<DonorCertificate[]>([]);
  const [emergencyKeys, setEmergencyKeys] = useState<EmergencyKey[]>([]);

  // Dynamic XP State
  const [currentXp, setCurrentXp] = useState(user.xp || 0);
  const [currentLevel, setCurrentLevel] = useState(user.level || 1);

  // Feedback state
  const [feedbackText, setFeedbackText] = useState('');
  const [isSubmittingFeedback, setIsSubmittingFeedback] = useState(false);

  // Emergency Search State
  const [searchBloodType, setSearchBloodType] = useState('All');
  const [searchCity, setSearchCity] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [emergencySearchResults, setEmergencySearchResults] = useState<User[]>([]);

  // Booking Modal State
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingRequest, setBookingRequest] = useState<BloodRequest | null>(null);
  const [bookingDate, setBookingDate] = useState('');
  const [bookingTime, setBookingTime] = useState('');

  // Calculations
  const xpInCurrentLevel = currentXp % 100;
  const progress = (xpInCurrentLevel / 100) * 100;

  useEffect(() => {
    loadData();
  }, [user.id]);

  const loadData = async () => {
    const health = await getHealthTip('Donor');
    setHealthTip(health);
    const apps = await API.getAppointments();
    setAppointments(apps);
    const reqs = await API.getDonationRequests();
    // Assuming donor should see public blood requests feed
    setBloodRequests(MockBackend.getBloodRequestsFeed()); 
    setCertificates(MockBackend.getMyCertificates(user.id));
    setEmergencyKeys(MockBackend.getEmergencyKeys());
    setAchievements(MockBackend.getAchievements());
  };

  const handleVerify = () => {
    if (MockBackend.verifyDonorKey(specialKey)) {
      setIsVerified(true);
      alert("Verified successfully!");
    } else {
      alert("Invalid Key");
    }
  };

  const simulateDonationXp = () => {
    const earned = 25;
    const newXp = currentXp + earned;
    setCurrentXp(newXp);

    // Check for level up
    const newLevel = Math.floor(newXp / 100) + 1;
    if (newLevel > currentLevel) {
      setCurrentLevel(newLevel);
      alert(`🎉 LEVEL UP! You are now Level ${newLevel}!`);
    } else {
      alert(`Donation Complete! You earned ${earned} XP!`);
    }
  };

  const handleFeedbackSubmit = async () => {
    if (!feedbackText.trim()) return;
    setIsSubmittingFeedback(true);
    const f: Feedback = {
      id: `f-${Date.now()}`,
      userId: user.id,
      userRole: user.role,
      message: feedbackText,
      date: new Date().toISOString().split('T')[0]
    };
    await API.addFeedback(f);
    setIsSubmittingFeedback(false);
    setFeedbackText('');
    alert("Feedback received by Admin.");
    setActiveTab('dashboard');
  };

  const openBookingModal = (request: BloodRequest) => {
    setBookingRequest(request);
    setBookingDate(new Date().toISOString().split('T')[0]); 
    setShowBookingModal(true);
  };

  const confirmBooking = async () => {
    if (!bookingRequest || !bookingDate || !bookingTime) return;

    const newApp: Appointment = {
      id: Date.now().toString(),
      hospitalName: bookingRequest.requesterName,
      date: bookingDate,
      time: bookingTime,
      status: 'Scheduled'
    };
    await API.scheduleAppointment(newApp);

    // Also create a pending donation entry for admin
    const newDonationReq: DonationRequest = {
      id: `don-${Date.now()}`,
      donorName: user.name,
      bloodType: user.bloodType || 'Unknown',
      status: 'Pending',
      date: bookingDate,
      urgency: 'Medium',
      hospital: bookingRequest.requesterName
    };
    await API.addDonationRequest(newDonationReq);

    await loadData();
    setCurrentXp(prev => prev + 15);

    alert(`Appointment locked with ${bookingRequest.requesterName}. +15 XP Earned!`);
    setShowBookingModal(false);
    setBookingRequest(null);
  };

  const handleEmergencySearch = async () => {
    setIsSearching(true);
    setEmergencySearchResults([]);
    await new Promise(resolve => setTimeout(resolve, 2000));
    try {
      const results = await findDonorsWithAI(searchBloodType, searchCity);
      setEmergencySearchResults(results);
    } catch (error) {
      console.error("Search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleFileUpload = () => {
    setTimeout(() => {
      const newCert: DonorCertificate = {
        id: Date.now().toString(),
        donorId: user.id,
        date: new Date().toISOString().split('T')[0],
        hospitalName: 'Verified Clinical Center',
        imageUrl: 'placeholder'
      };
      // In real app would call API.addCertificate if existed
      setCertificates([...certificates, newCert]);
      setCurrentXp(prev => prev + 20);
      alert("Certificate Decrypted & Uploaded! +20 XP Earned.");
    }, 1000);
  };

  const showFakeAlert = (msg: string) => alert(`Secure Comms: ${msg}`);

  // --- Render Sections ---

  const LevelProgressCard = () => (
    <div className="bg-gradient-to-br from-gray-900 via-gray-800 to-blood-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group border border-white/5">
      <div className="absolute top-0 right-0 -mt-10 -mr-10 w-80 h-80 bg-blood-600 rounded-full blur-[100px] opacity-20 group-hover:opacity-30 transition-opacity duration-700"></div>
      <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-10">
        <div className="flex items-center gap-8">
          <div className="relative">
            <div className="w-28 h-28 rounded-3xl bg-white/10 flex items-center justify-center border-4 border-blood-500 shadow-[0_0_40px_rgba(225,29,72,0.4)] rotate-3">
              <span className="text-5xl font-black text-white">{currentLevel}</span>
            </div>
            <div className="absolute -bottom-3 -right-3 bg-blood-600 p-2 rounded-2xl border-4 border-gray-900 shadow-xl">
              <Trophy size={20} className="text-yellow-400" />
            </div>
          </div>
          <div className="text-left">
            <p className="text-blood-400 text-xs font-black uppercase tracking-[0.3em] mb-2">Protocol Excellence</p>
            <h2 className="text-4xl font-black text-white mb-2 tracking-tight">ELITE LIFESAVER</h2>
            <div className="flex items-center gap-4 text-sm text-gray-400 font-bold">
              <div className="flex items-center gap-2 px-3 py-1 bg-white/10 rounded-full border border-white/5">
                <Sparkles size={14} className="text-yellow-500" />
                <span>{currentXp} XP</span>
              </div>
              <span className="text-gray-700">|</span>
              <span className="text-green-400 uppercase tracking-widest text-xs">Tier: Verified Veteran</span>
            </div>
          </div>
        </div>

        <div className="w-full md:w-5/12 space-y-5">
          <div className="flex justify-between items-end mb-1">
            <span className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em]">Rank Progression</span>
            <span className="text-2xl font-black text-blood-400 tracking-tighter">{Math.floor(progress)}%</span>
          </div>
          <div className="w-full bg-white/5 rounded-full h-6 p-1 border border-white/10 relative shadow-inner">
            <div 
              className="bg-gradient-to-r from-blood-600 via-blood-500 to-orange-500 h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_20px_rgba(225,29,72,0.4)]" 
              style={{ width: `${progress}%` }}
            >
              <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20"></div>
            </div>
          </div>
          <p className="text-right text-[10px] font-black text-gray-500 uppercase tracking-widest">{100 - xpInCurrentLevel} XP TO ASCENSION</p>
        </div>
      </div>
    </div>
  );

  const renderDashboard = () => (
    <div className="space-y-10 animate-fade-in-up">
       <LevelProgressCard />

       <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
         <div className="space-y-10">
            <div className="relative h-64 rounded-[3rem] overflow-hidden shadow-2xl transition-all hover:scale-[1.03] duration-500 group cursor-pointer border border-white/10">
               <div className="absolute inset-0 bg-gradient-to-br from-blood-600 to-blood-900 group-hover:from-blood-700 group-hover:to-blood-950 transition-all duration-500"></div>
               <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/diagonal-striped-brick.png')] opacity-10"></div>
               <div className="relative z-10 p-10 flex flex-col justify-between h-full text-white">
                 <div className="flex justify-between items-start">
                   <div>
                     <p className="text-[10px] uppercase font-black tracking-[0.4em] opacity-60 mb-2">Protocol Member ID</p>
                     <h3 className="font-black text-2xl tracking-[0.15em] flex items-center gap-3 font-mono">{user.id.toUpperCase()}</h3>
                   </div>
                   {isVerified ? (
                     <div className="bg-green-500/20 p-3 rounded-2xl backdrop-blur-xl border border-green-500/40 shadow-inner">
                       <CheckCircle className="text-green-400" size={32} />
                     </div>
                   ) : (
                     <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-xl border border-white/20">
                       <Lock className="text-white/50" size={32} />
                     </div>
                   )}
                 </div>
                 <div className="flex items-end gap-8">
                   <div className="bg-white/10 backdrop-blur-2xl rounded-3xl p-5 text-center min-w-[100px] border border-white/20 shadow-2xl">
                     <p className="text-[10px] opacity-60 uppercase font-black tracking-widest mb-1">Group</p>
                     <p className="text-5xl font-black tracking-tighter">{user.bloodType || '??'}</p>
                   </div>
                   <div className="flex-1 pb-2">
                     <p className="text-2xl font-black tracking-tight leading-none">{user.name.toUpperCase()}</p>
                     <p className="text-[10px] opacity-60 uppercase font-black tracking-[0.3em] mt-2">Active Since {user.joinDate || '2023'}</p>
                   </div>
                 </div>
               </div>
            </div>

            {!isVerified && (
              <div className="bg-white p-10 rounded-[3rem] shadow-2xl border border-gray-100">
                <h3 className="font-black text-gray-900 text-xl mb-3 flex items-center gap-3"><Lock size={22} className="text-yellow-500" /> Security Protocol</h3>
                <p className="text-sm text-gray-500 font-medium mb-8">Enter the high-priority validation key provided by clinical administration.</p>
                <div className="flex gap-4">
                  <input type="text" value={specialKey} onChange={(e) => setSpecialKey(e.target.value)} className="flex-1 bg-gray-50 border-none rounded-2xl px-6 py-4 text-sm font-bold outline-none focus:ring-2 focus:ring-blood-500 transition-all shadow-inner" placeholder="VAL-PROTOCOL-XXX" />
                  <Button onClick={handleVerify} className="px-8 rounded-2xl font-black uppercase tracking-widest text-xs">Verify</Button>
                </div>
              </div>
            )}
         </div>

         <div className="lg:col-span-2 space-y-8">
            <div className="grid grid-cols-2 gap-8">
               <div className="bg-white p-10 rounded-[3rem] shadow-xl border border-gray-100 group hover:border-blood-200 transition-all flex flex-col justify-center">
                  <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.3em] mb-4">Network Impact</p>
                  <p className="text-6xl font-black text-gray-900 group-hover:text-blood-600 transition-colors tracking-tighter">12</p>
                  <p className="text-xs text-green-600 mt-4 font-black uppercase tracking-widest flex items-center gap-2"><TrendingUp size={14}/> Top 5% Contributor</p>
               </div>
               <div className="bg-white p-10 rounded-[3rem] shadow-xl border border-gray-100 group hover:border-green-200 transition-all flex flex-col justify-center">
                  <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.3em] mb-4">Lives Preserved</p>
                  <p className="text-6xl font-black text-green-600 tracking-tighter">36</p>
                  <p className="text-xs text-gray-400 mt-4 font-black uppercase tracking-widest">Protocol Grade: <span className="text-gray-900 font-black">Platinum</span></p>
               </div>
            </div>

            <div className="bg-white p-10 rounded-[3rem] shadow-xl border border-gray-100">
              <div className="flex justify-between items-center mb-8">
                <h3 className="font-black text-gray-900 text-xl tracking-tight uppercase">Clinical Appointments</h3>
                <Button variant="outline" className="text-[10px] py-2 px-5 h-auto font-black uppercase tracking-widest rounded-xl" onClick={() => setActiveTab('requests')}>Schedule New</Button>
              </div>
              {appointments.length > 0 ? (
                <div className="space-y-5">
                  {appointments.map((app, i) => (
                    <div key={i} className="flex items-center justify-between p-6 bg-gray-50/50 rounded-2xl border border-gray-100 hover:bg-white hover:shadow-2xl transition-all cursor-pointer group">
                       <div className="flex items-center gap-6">
                          <div className="p-4 bg-white text-blood-600 rounded-2xl shadow-xl group-hover:scale-110 transition-transform"><Calendar size={24}/></div>
                          <div>
                             <p className="font-black text-gray-900 text-lg leading-tight mb-1">{app.hospitalName}</p>
                             <p className="text-xs text-gray-400 font-black uppercase tracking-widest">{app.date} @ {app.time}</p>
                          </div>
                       </div>
                       <span className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] shadow-sm ${app.status === 'Scheduled' ? 'bg-blue-100 text-blue-700' : 'bg-green-100 text-green-700'}`}>{app.status}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-16 bg-gray-50 rounded-[2rem] border-4 border-dashed border-gray-100">
                   <Clock className="mx-auto text-gray-200 mb-4" size={48} />
                   <p className="text-gray-400 text-sm font-black uppercase tracking-[0.2em]">Queue is currently clear</p>
                </div>
              )}
            </div>
         </div>
       </div>
    </div>
  );

  const renderFeedback = () => (
    <div className="max-w-3xl mx-auto space-y-10 animate-fade-in-up">
       <div className="bg-gray-900 p-12 rounded-[3.5rem] text-white shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 right-0 w-64 h-64 bg-blood-600 rounded-full blur-[100px] opacity-30 -mt-20 -mr-20"></div>
          <h2 className="text-4xl font-black mb-4 tracking-tight">SYSTEM FEEDBACK</h2>
          <p className="text-gray-400 text-lg font-medium leading-relaxed">Your professional feedback is transmitted directly to the Admin console for system optimization.</p>
       </div>

       <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-gray-100 space-y-10">
          <div className="space-y-4">
             <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] px-4">Detailed Message</label>
             <textarea 
               value={feedbackText} 
               onChange={(e) => setFeedbackText(e.target.value)}
               className="w-full h-56 p-8 bg-gray-50 rounded-[2rem] border-none focus:ring-2 focus:ring-blood-500 font-bold text-lg shadow-inner outline-none transition-all"
               placeholder="Describe clinic conditions, system anomalies, or protocol suggestions..."
             />
          </div>
          <Button 
            onClick={handleFeedbackSubmit} 
            isLoading={isSubmittingFeedback} 
            disabled={!feedbackText.trim()}
            className="w-full py-6 text-xl font-black uppercase tracking-[0.3em] rounded-[1.5rem] shadow-2xl shadow-blood-500/30"
          >
             Secure Transmission
          </Button>
       </div>
    </div>
  );

  const renderRequests = () => (
    <div className="space-y-8 animate-fade-in-up">
      <div className="bg-white p-10 rounded-[3rem] border border-gray-100 shadow-xl flex justify-between items-center">
         <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">Live Clinical Demand</h2>
           <p className="text-sm text-gray-400 font-black uppercase tracking-widest mt-1">Real-time requirements from medical facilities</p>
         </div>
         <div className="p-4 bg-blood-50 text-blood-600 rounded-2xl animate-pulse"><Activity size={32}/></div>
      </div>

      <div className="grid grid-cols-1 gap-6">
         {bloodRequests.map(req => (
           <div key={req.id} className={`bg-white p-10 rounded-[3rem] border-l-[12px] shadow-sm hover:shadow-2xl transition-all group ${req.urgency === 'Critical' ? 'border-l-red-600' : req.urgency === 'High' ? 'border-l-orange-500' : 'border-l-blue-500'}`}>
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10">
                 <div className="flex items-center gap-8">
                    <div className={`w-20 h-20 rounded-3xl flex items-center justify-center text-white shadow-2xl group-hover:rotate-6 transition-transform ${req.requesterType === 'Hospital' ? 'bg-blue-600' : 'bg-green-600'}`}>
                       {req.requesterType === 'Hospital' ? <Building2 size={36}/> : <UserIcon size={36}/>}
                    </div>
                    <div className="text-left">
                       <div className="flex items-center gap-4 mb-2">
                          <h3 className="font-black text-2xl text-gray-900 tracking-tight">{req.requesterName}</h3>
                          {req.urgency === 'Critical' && <span className="px-4 py-1.5 bg-red-100 text-red-600 text-[10px] font-black uppercase tracking-widest rounded-full animate-pulse">Critical Priority</span>}
                       </div>
                       <p className="text-sm text-gray-500 font-black uppercase tracking-widest flex items-center gap-3"><MapPin size={16} className="text-blood-600"/> {req.location} • {req.distance} Radius</p>
                    </div>
                 </div>

                 <div className="flex items-center gap-8 w-full md:w-auto bg-gray-50 p-6 rounded-[2rem] border border-gray-100 shadow-inner">
                    <div className="text-center px-8 border-r border-gray-200">
                       <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest mb-1">Group</p>
                       <p className="text-5xl font-black text-blood-600 tracking-tighter">{req.bloodType}</p>
                       <p className="text-[10px] font-black text-gray-400 mt-1">{req.units} UNITS</p>
                    </div>
                    <Button className="flex-1 md:flex-none py-5 px-10 rounded-2xl shadow-xl shadow-blood-500/20 font-black uppercase tracking-widest text-xs" onClick={() => openBookingModal(req)}>Authorize Slot</Button>
                 </div>
              </div>
           </div>
         ))}
      </div>
    </div>
  );

  const BookingModal = () => {
    if (!showBookingModal || !bookingRequest) return null;
    return (
      <div className="fixed inset-0 bg-black/85 backdrop-blur-xl z-[100] flex items-center justify-center p-4 animate-fade-in-up">
        <div className="bg-white rounded-[3.5rem] w-full max-w-md overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.4)] border border-white/10">
           <div className="bg-gray-900 p-8 flex justify-between items-center text-white">
             <h3 className="font-black text-xl tracking-tight uppercase tracking-widest">Protocol Authorization</h3>
             <button onClick={() => setShowBookingModal(false)} className="hover:bg-white/10 p-2 rounded-full transition-colors"><X size={24}/></button>
           </div>
           <div className="p-10 space-y-10">
              <div className="bg-gray-50 p-8 rounded-[2rem] shadow-inner border border-gray-100 text-left">
                 <p className="text-[10px] text-gray-400 uppercase font-black tracking-[0.3em] mb-2">Target Facility</p>
                 <p className="text-2xl font-black text-gray-900 leading-tight mb-2">{bookingRequest.requesterName}</p>
                 <p className="text-xs font-bold text-gray-500 flex items-center gap-2"><MapPin size={14} className="text-blood-600"/> {bookingRequest.location}</p>
              </div>

              <div className="space-y-4 text-left">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] px-4">Clinical Window</label>
                 <input 
                   type="date" 
                   value={bookingDate} 
                   onChange={(e) => setBookingDate(e.target.value)}
                   className="w-full px-8 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-blood-500 outline-none font-black text-xl shadow-inner"
                 />
              </div>

              <div className="space-y-5 text-left">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] px-4">Operation Slots</label>
                 <div className="grid grid-cols-2 gap-4">
                   {['09:00 AM', '11:00 AM', '02:00 PM', '04:00 PM'].map(time => (
                     <button 
                       key={time} 
                       onClick={() => setBookingTime(time)}
                       className={`px-4 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border-4 ${bookingTime === time ? 'bg-blood-600 text-white border-blood-600 shadow-2xl scale-[1.03]' : 'bg-gray-50 text-gray-400 border-transparent hover:bg-white hover:border-gray-100'}`}
                     >
                       {time}
                     </button>
                   ))}
                 </div>
              </div>

              <Button onClick={confirmBooking} disabled={!bookingDate || !bookingTime} className="w-full py-6 text-xl font-black rounded-3xl tracking-[0.3em] shadow-2xl shadow-blood-500/40 uppercase active:scale-95 transition-transform">Authorize Deployment</Button>
           </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-10 pb-12">
      <div className="bg-white p-3 rounded-[2rem] shadow-xl border border-gray-100 inline-flex flex-wrap gap-2 w-full lg:w-auto">
         <button onClick={() => setActiveTab('dashboard')} className={`px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'dashboard' ? 'bg-gray-900 text-white shadow-2xl' : 'text-gray-400 hover:bg-gray-50'}`}>Command Center</button>
         <button onClick={() => setActiveTab('requests')} className={`px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'requests' ? 'bg-blood-600 text-white shadow-2xl' : 'text-gray-400 hover:bg-gray-50'}`}>Global Demand</button>
         <button onClick={() => setActiveTab('certificates')} className={`px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'certificates' ? 'bg-blue-600 text-white shadow-2xl' : 'text-gray-400 hover:bg-gray-50'}`}>Secured Vault</button>
         <button onClick={() => setActiveTab('feedback')} className={`px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'feedback' ? 'bg-orange-600 text-white shadow-2xl' : 'text-gray-400 hover:bg-gray-50'}`}>Feedback Comms</button>
      </div>

      <div className="min-h-[600px]">
         {activeTab === 'dashboard' && renderDashboard()}
         {activeTab === 'requests' && renderRequests()}
         {activeTab === 'certificates' && certificates.length > 0 && (
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 animate-fade-in-up">
              {certificates.map(cert => (
                <div key={cert.id} className="bg-white p-10 rounded-[3rem] shadow-xl border border-gray-100 group relative overflow-hidden">
                   <div className="aspect-square bg-gray-50 rounded-[2rem] mb-8 flex items-center justify-center relative overflow-hidden shadow-inner">
                      <FileText size={80} className="text-gray-100 group-hover:scale-125 transition-transform duration-1000" />
                      <div className="absolute inset-0 bg-blood-900/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-sm">
                         <Button variant="secondary" className="text-[10px] font-black px-8 py-4 rounded-2xl shadow-2xl uppercase tracking-widest" onClick={() => showFakeAlert('Decrypting Document...')}>Decipher Content</Button>
                      </div>
                   </div>
                   <h4 className="font-black text-gray-900 text-2xl tracking-tight mb-2 uppercase">{cert.hospitalName}</h4>
                   <p className="text-[10px] font-black text-gray-400 flex items-center gap-3 uppercase tracking-widest"><Calendar size={14} className="text-blood-600"/> Verified Entry: {cert.date}</p>
                </div>
              ))}
           </div>
         )}
         {activeTab === 'feedback' && renderFeedback()}
         {activeTab === 'emergency' && (
           <div className="text-center py-40 font-black uppercase tracking-[0.4em] text-gray-300">Administrative Key Required</div>
         )}
         {activeTab === 'registration' && (
           <div className="text-center py-40 font-black uppercase tracking-[0.4em] text-gray-300">Interface Loading...</div>
         )}
      </div>

      <BookingModal />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Heart, Calendar, CheckCircle, Lock, MapPin, Award, Clock, CreditCard, Share2, FileText, Upload, Eye, Activity, Trophy, Building2, User as UserIcon, ArrowRight, AlertCircle, Search, Phone, MessageCircle, X, Key, Sparkles, TrendingUp, Droplet, Send, ShieldCheck } from 'lucide-react';
import { User, Achievement, Appointment, BloodRequest, DonorCertificate, EmergencyKey, Feedback, DonationRequest } from '../types';
import { API } from '../services/api';
import { MockBackend } from '../services/mockBackend';
import { Button } from './Button';
import { getHealthTip, findDonorsWithAI } from '../services/geminiService';

interface DonorPanelProps {
  user: User;
}

type ActiveTab = 'dashboard' | 'requests' | 'certificates' | 'registration' | 'emergency' | 'feedback';

export const DonorPanel: React.FC<DonorPanelProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<ActiveTab>('dashboard');

  // Data States
  const [specialKey, setSpecialKey] = useState('');
  const [isVerified, setIsVerified] = useState(user.isVerified);
  const [healthTip, setHealthTip] = useState('');
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [bloodRequests, setBloodRequests] = useState<BloodRequest[]>([]);
  const [certificates, setCertificates] = useState<DonorCertificate[]>([]);
  const [emergencyKeys, setEmergencyKeys] = useState<EmergencyKey[]>([]);

  // Dynamic XP State
  const [currentXp, setCurrentXp] = useState(user.xp || 0);
  const [currentLevel, setCurrentLevel] = useState(user.level || 1);

  // Feedback state
  const [feedbackText, setFeedbackText] = useState('');
  const [isSubmittingFeedback, setIsSubmittingFeedback] = useState(false);

  // Emergency Search State
  const [searchBloodType, setSearchBloodType] = useState('All');
  const [searchCity, setSearchCity] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [emergencySearchResults, setEmergencySearchResults] = useState<User[]>([]);

  // Booking Modal State
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingRequest, setBookingRequest] = useState<BloodRequest | null>(null);
  const [bookingDate, setBookingDate] = useState('');
  const [bookingTime, setBookingTime] = useState('');

  // Calculations
  const xpInCurrentLevel = currentXp % 100;
  const progress = (xpInCurrentLevel / 100) * 100;

  useEffect(() => {
    loadData();
  }, [user.id]);

  const loadData = async () => {
    const health = await getHealthTip('Donor');
    setHealthTip(health);
    const apps = await API.getAppointments();
    setAppointments(apps);
    const reqs = await API.getDonationRequests();
    // Assuming donor should see public blood requests feed
    setBloodRequests(MockBackend.getBloodRequestsFeed()); 
    setCertificates(MockBackend.getMyCertificates(user.id));
    setEmergencyKeys(MockBackend.getEmergencyKeys());
    setAchievements(MockBackend.getAchievements());
  };

  const handleVerify = () => {
    if (MockBackend.verifyDonorKey(specialKey)) {
      setIsVerified(true);
      alert("Verified successfully!");
    } else {
      alert("Invalid Key");
    }
  };

  const simulateDonationXp = () => {
    const earned = 25;
    const newXp = currentXp + earned;
    setCurrentXp(newXp);

    // Check for level up
    const newLevel = Math.floor(newXp / 100) + 1;
    if (newLevel > currentLevel) {
      setCurrentLevel(newLevel);
      alert(`🎉 LEVEL UP! You are now Level ${newLevel}!`);
    } else {
      alert(`Donation Complete! You earned ${earned} XP!`);
    }
  };

