import React, { useState, useEffect } from 'react';
import { Search, MapPin, Droplet, Phone, MessageCircle, Activity, AlertTriangle, Filter, ArrowRight, ChevronDown, ChevronUp, Send, X } from 'lucide-react';
import { User, Hospital, BloodStock, Feedback, DonationRequest } from '../types';
import { API } from '../services/api';
import { Button } from './Button';

export const UserPanel: React.FC = () => {
  const [bloodType, setBloodType] = useState('All');
  const [city, setCity] = useState('');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [hospitals, setHospitals] = useState<Hospital[]>([]);
  const [bloodStocks, setBloodStocks] = useState<BloodStock[]>([]);
  const [sosActive, setSosActive] = useState(false);

  // UI States
  const [isSearching, setIsSearching] = useState(false);
  const [showAllHospitals, setShowAllHospitals] = useState(false);
  const [showAllStocks, setShowAllStocks] = useState(false);
  const [showFeedbackModal, setShowFeedbackModal] = useState(false);
  const [feedbackText, setFeedbackText] = useState('');
  const [isSubmittingFeedback, setIsSubmittingFeedback] = useState(false);

  useEffect(() => {
    loadInitialData();
  }, []);

  const loadInitialData = async () => {
    const s = await API.getBloodStocks();
    setBloodStocks(s);
  };

  const handleSearch = async () => {
    setIsSearching(true);
    setSearchResults([]); 
    await new Promise(resolve => setTimeout(resolve, 2000));
    try {
      const results = await API.getUsers(); 
      const filtered = results.filter(u => 
        u.role === 'DONOR' && 
        (bloodType === 'All' || u.bloodType === bloodType) &&
        (city === '' || u.location?.toLowerCase().includes(city.toLowerCase()))
      );
      setSearchResults(filtered);
    } catch (error) {
      console.error("Search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSOS = () => {
    setSosActive(!sosActive);
    if (!sosActive) {
      alert("EMERGENCY: All nearby donors have been alerted (Simulated). Help is on the way.");
    }
  };

  const handleFeedbackSubmit = () => {
    if (!feedbackText.trim()) return;
    setIsSubmittingFeedback(true);
    setTimeout(() => {
      setIsSubmittingFeedback(false);
      setFeedbackText('');
      setShowFeedbackModal(false);
      alert("Feedback received by administration (Simulated).");
    }, 1000);
  };

  const showFakeAlert = (msg: string) => alert(`Mock Data: ${msg}`);

  const displayedStocks = showAllStocks ? bloodStocks : bloodStocks.slice(0, 3);

  return (
    <div className="space-y-10 pb-12">
      {/* Top Action Bar & Stats */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* SOS Section */}
        <div className={`rounded-[3rem] p-10 shadow-2xl transition-all duration-700 flex flex-col justify-between relative overflow-hidden ${sosActive ? 'bg-red-600 text-white' : 'bg-white text-gray-800 border border-gray-100'}`}>
          <div className="relative z-10">
             <div className="flex items-center gap-4 mb-6">
               <div className={`p-4 rounded-2xl shadow-inner ${sosActive ? 'bg-white/20' : 'bg-red-50 text-red-600'}`}>
                 <AlertTriangle size={32} />
               </div>
               <h2 className="text-3xl font-black tracking-tighter">EMERGENCY SOS</h2>
             </div>
             <p className={`mb-8 text-lg font-medium leading-relaxed ${sosActive ? 'text-red-100' : 'text-gray-500'}`}>
               {sosActive ? 'CRITICAL: Broadcasting urgent requirement to the global donor network. Real-time tracking enabled.' : 'Instantly notify all registered donors in your current GPS range for life-critical blood needs.'}
             </p>
             <Button 
              onClick={handleSOS}
              className={`w-full py-5 text-xl font-black rounded-2xl border-none tracking-widest uppercase transition-transform active:scale-95 ${sosActive ? 'bg-white text-red-600 hover:bg-gray-100 shadow-2xl' : 'bg-red-600 text-white hover:bg-red-700 shadow-2xl shadow-red-500/40'}`}
             >
               {sosActive ? 'Abort SOS Protocol' : 'Broadcast Emergency'}
             </Button>
          </div>
          {sosActive && (
             <div className="absolute inset-0 z-0">
               <div className="absolute inset-0 bg-red-600 animate-pulse"></div>
               <div className="absolute -top-32 -right-32 w-80 h-80 bg-white/10 rounded-full blur-[100px]"></div>
             </div>
          )}
        </div>

        {/* Blood Stock Visuals */}
        <div className="lg:col-span-2 bg-white p-10 rounded-[3rem] shadow-2xl border border-gray-100">
