             <h2 className="text-2xl font-black tracking-tighter flex items-center gap-3"><Activity className="text-blood-600" size={32}/> GLOBAL STOCK INDEX</h2>
             <Button 
                variant="outline" 
                className="text-[10px] gap-2 font-black uppercase tracking-widest rounded-xl border-gray-100 h-auto py-2 px-4" 
