        <div className="p-10 bg-gray-50 min-h-[400px]">
           {isSearching ? (
              <div className="flex flex-col items-center justify-center h-[300px] space-y-6">
                <div className="w-16 h-16 border-4 border-blood-200 border-t-blood-600 rounded-full animate-spin"></div>
                <p className="text-gray-400 font-black tracking-[0.3em] animate-pulse uppercase">DECRYPTING DONOR PROFILES...</p>
              </div>
           ) : searchResults.length > 0 ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
