                       <div className="flex-1">
                         <h3 className="font-black text-gray-900 text-xl tracking-tight">{donor.name}</h3>
                         <p className="text-xs text-gray-400 font-bold uppercase tracking-widest flex items-center gap-2 mb-2"><MapPin size={12} className="text-blood-600" /> {donor.location || 'Roaming'}</p>
