import { User, UserRole, BloodStock, DonationRequest, Appointment, Feedback, SecurityLog, BloodRequest } from "../types";
import { DB } from "./db";

const delay = (ms: number = 600) => new Promise(resolve => setTimeout(resolve, ms));

export const API = {
  // --- AUTH ---
  login: async (username: string, password: string, role: UserRole): Promise<User | null> => {
    await delay(800);
    const users = DB.getUsers();
    const user = users.find(u => 
      u.username.toLowerCase() === username.toLowerCase() && 
      (u as any).password === password &&
      u.role === role
    );

    if (user) {
      DB.addLog({ 
        id: `log-${Date.now()}`, 
        severity: 'Low', 
        message: `${role} Login Successful: ${user.username}`, 
        timestamp: new Date().toLocaleString() 
      });
      return user;
    }
    return null;
  },

  register: async (userData: Partial<User & { password?: string }>): Promise<User> => {
    await delay(1000);
    const users = DB.getUsers();
    if (users.some(u => u.username.toLowerCase() === userData.username?.toLowerCase())) {
      throw new Error("Username already taken.");
    }

    const newUser: User = {
      id: `u-${Date.now()}`,
      username: userData.username || '',
      name: userData.username || '',
      role: userData.role || UserRole.USER,
      bloodType: userData.bloodType,
      location: userData.location,
      phone: userData.phone,
      email: userData.email,
      address: userData.address,
      joinDate: new Date().toISOString().split('T')[0],
      status: 'Active',
      level: 1,
      xp: 0
    };

    (newUser as any).password = userData.password;
    users.push(newUser);
    DB.saveUsers(users);

    DB.addLog({ id: `log-${Date.now()}`, severity: 'Low', message: `New ${newUser.role} Registered: ${newUser.username}`, timestamp: new Date().toLocaleString() });
    return newUser;
  },

  getUsers: async (): Promise<User[]> => {
    await delay(300);
    return DB.getUsers();
  },

  toggleUserStatus: async (userId: string): Promise<string | null> => {
    await delay(400);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user) {
      user.status = user.status === 'Active' ? 'Blocked' : 'Active';
      DB.saveUsers(users);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Medium', message: `User status changed: ${user.name} (${user.status})`, timestamp: new Date().toLocaleString() });
      return user.status;
    }
    return null;
  },

  promoteDonor: async (userId: string): Promise<number | null> => {
    await delay(500);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user && user.role === UserRole.DONOR) {
      user.level = (user.level || 1) + 1;
      user.xp = (user.xp || 0) + 100;
      DB.saveUsers(users);
      return user.level;
    }
    return null;
  },

  getBloodStocks: async (): Promise<BloodStock[]> => {
    await delay(400);
    return DB.getStocks();
  },

  getDonationRequests: async (): Promise<DonationRequest[]> => {
    await delay(300);
    return DB.getRequests();
  },

  addDonationRequest: async (req: DonationRequest): Promise<void> => {
    await delay(500);
    DB.addRequest(req);
    DB.addLog({ id: `log-${Date.now()}`, severity: 'Medium', message: `New donation submitted by ${req.donorName}`, timestamp: new Date().toLocaleString() });
  },

  getBloodNeeds: async (): Promise<BloodRequest[]> => {
    await delay(300);
    return DB.getBloodNeeds();
  },

  getAppointments: async (): Promise<Appointment[]> => {
    await delay(200);
    return DB.getAppointments();
  },

  scheduleAppointment: async (app: Appointment): Promise<void> => {
    await delay(600);
    DB.saveAppointment(app);
  },

  getFeedbacks: async (): Promise<Feedback[]> => {
    await delay(200);
    return DB.getFeedbacks();
  },

  addFeedback: async (feedback: Feedback): Promise<void> => {
    await delay(400);
    const feedbacks = DB.getFeedbacks();
    feedbacks.unshift(feedback);
    DB.saveFeedbacks(feedbacks);
    DB.addLog({ id: `log-${Date.now()}`, severity: 'Low', message: `Feedback received from ${feedback.userId}`, timestamp: new Date().toLocaleString() });
  },

  replyToFeedback: async (feedbackId: string, reply: string): Promise<void> => {
    await delay(400);
    const feedbacks = DB.getFeedbacks();
    const index = feedbacks.findIndex(f => f.id === feedbackId);
    if (index !== -1) {
      feedbacks[index].reply = reply;
      DB.saveFeedbacks(feedbacks);
    }
  },

  getSecurityLogs: async (): Promise<SecurityLog[]> => {
    await delay(200);
    return DB.getLogs();
  },

  issueEmergencyKey: async (userId: string): Promise<string> => {
    await delay(500);
    const code = `GRANT-${Math.floor(1000 + Math.random() * 8999)}`;
    DB.addLog({ id: `log-${Date.now()}`, severity: 'High', message: `Emergency Key Issued: ${code}`, timestamp: new Date().toLocaleString() });
    return code;
  }
};

