                       <p className="text-xs font-bold text-gray-400 flex items-center gap-1 uppercase tracking-widest"><MapPin size={12} className="text-blood-600"/> {res.location}</p>
                       <div className="mt-4 flex gap-2">
                          <div className="bg-green-50 text-green-700 px-4 py-2 rounded-xl text-xs font-black tracking-widest flex items-center gap-2 border border-green-100 shadow-sm"><Phone size={14}/> {res.phone}</div>
                          <Button className="text-[10px] font-black uppercase tracking-widest h-auto py-2 px-5 rounded-xl shadow-xl shadow-blood-500/10" onClick={() => alert(`Contacting ${res.name}...`)}>Authorize Contact</Button>
                       </div>
                    </div>
                 </div>
               ))}
            </div>
          </div>
       ) : (
          <div className="text-center py-20 bg-gray-50 rounded-[3rem] border-4 border-dashed border-gray-100">
             <p className="text-gray-400 font-black uppercase tracking-widest text-sm opacity-50">Results will display upon scan initialization.</p>
          </div>
       )}
    </div>
  );

  return (
    <div className="space-y-8 pb-12">
      <div className="bg-white p-2.5 rounded-[2rem] shadow-sm border border-gray-100 inline-flex flex-wrap gap-2 w-full md:w-auto">
         <button onClick={() => setActiveTab('dashboard')} className={`px-8 py-3.5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'dashboard' ? 'bg-gray-900 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Command Center</button>
         <button onClick={() => setActiveTab('users')} className={`px-8 py-3.5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>User Network</button>
         <button onClick={() => setActiveTab('feedback')} className={`px-8 py-3.5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'feedback' ? 'bg-orange-500 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Feedback Protocol</button>
         <button onClick={() => setActiveTab('search')} className={`px-8 py-3.5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'search' ? 'bg-blood-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Network Scan</button>
      </div>

      <div className="min-h-[500px]">
         {activeTab === 'dashboard' && renderDashboard()}
         {activeTab === 'users' && renderUsers()}
         {activeTab === 'feedback' && renderFeedback()}
         {activeTab === 'search' && renderSearch()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Search, MapPin, Droplet, Phone, MessageCircle, Activity, AlertTriangle, Filter, ArrowRight, ChevronDown, ChevronUp, Send, X } from 'lucide-react';
