      const user = JSON.parse(localStorage.getItem('lifeflow_current_user') || '{}');
      const newReq: DonationRequest = {
        id: `sos-${Date.now()}`,
        donorName: user.name || 'Emergency Requester',
        bloodType: user.bloodType || 'Urgent',
        status: 'Pending',
        date: new Date().toISOString().split('T')[0],
        urgency: 'Critical',
        hospital: 'SOS BROADCAST'
