             >
               {showAllStocks ? 'Compact View' : 'Full Index'} {showAllStocks ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
             </Button>
           </div>

           <div className="space-y-8 max-h-[350px] overflow-y-auto pr-4 custom-scrollbar">
              {displayedStocks.map(stock => (
