                  <div className="flex justify-between text-sm font-black mb-3 items-end">
                    <span className="flex items-center gap-4">
                      <span className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xs font-black shadow-inner group-hover:bg-blood-600 group-hover:text-white transition-colors">{stock.bloodType}</span>
                      <div className="text-left">
                        <p className="text-gray-900 leading-tight">{stock.hospitalName}</p>
                        <p className="text-[10px] text-gray-400 uppercase tracking-widest">{stock.city}</p>
                      </div>
                    </span>
                    <span className={`text-sm tracking-tighter ${stock.units < 10 ? 'text-red-600' : 'text-green-600'}`}>{stock.units} UNITS REMAINING</span>
                  </div>
                  <div className="w-full h-4 bg-gray-100 rounded-full overflow-hidden shadow-inner p-1">
                    <div 
                      className={`h-full rounded-full relative overflow-hidden transition-all duration-1000 ease-out ${stock.units < 10 ? 'bg-gradient-to-r from-red-600 to-red-400 shadow-[0_0_15px_rgba(220,38,38,0.3)]' : 'bg-gradient-to-r from-green-600 to-green-400 shadow-[0_0_15px_rgba(22,163,74,0.3)]'}`}
                      style={{ width: `${Math.min((stock.units / stock.maxCapacity) * 100, 100)}%` }}
                    >
                       <div className="absolute inset-0 bg-white/20 w-full h-full animate-[shimmer_2s_infinite]"></div>
                    </div>
                  </div>
                </div>
              ))}
