        </div>
      </div>

      <div className="bg-white rounded-[3rem] shadow-2xl border border-gray-100 overflow-hidden">
        <div className="p-10 border-b border-gray-100 bg-gray-50/50">
           <h2 className="text-3xl font-black tracking-tighter mb-8">SOURCE DONOR NETWORK</h2>
           <div className="flex flex-col md:flex-row gap-6">
              <div className="flex-1 relative">
                 <Droplet className="absolute left-6 top-1/2 -translate-y-1/2 text-blood-600" size={24}/>
                 <select 
