                    <div className="flex items-center gap-6 mb-8">
                       <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-blood-500 to-blood-700 flex items-center justify-center text-white font-black text-2xl shadow-xl shadow-blood-500/20 group-hover:rotate-6 transition-transform">
                          {donor.bloodType}
                       </div>
                       <div className="flex-1">
                         <h3 className="font-black text-gray-900 text-xl tracking-tight">{donor.name}</h3>
                         <p className="text-xs text-gray-400 font-bold uppercase tracking-widest flex items-center gap-2 mb-2"><MapPin size={12} className="text-blood-600" /> {donor.location || 'Roaming'}</p>
                         {donor.phone && (
                           <p className="text-sm font-black text-green-600 flex items-center gap-2"><Phone size={14} /> {donor.phone}</p>
