           ) : (
             <div className="flex flex-col items-center justify-center h-[300px] text-gray-400 py-12">
                <div className="w-24 h-24 bg-white shadow-xl rounded-full flex items-center justify-center mb-8 border border-gray-50">
                   <Search size={40} className="text-gray-200" />
