import React, { useState, useEffect } from 'react';
import { Search, MapPin, Droplet, Phone, MessageCircle, Activity, AlertTriangle, Filter, ArrowRight, ChevronDown, ChevronUp } from 'lucide-react';
import { User, Hospital, BloodStock, Feedback, DonationRequest } from '../types';
import { API } from '../services/api';
import { findDonorsWithAI } from '../services/geminiService';
import { Button } from './Button';

export const UserPanel: React.FC = () => {
  const [bloodType, setBloodType] = useState('All');
  const [city, setCity] = useState('');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [bloodStocks, setBloodStocks] = useState<BloodStock[]>([]);
  const [sosActive, setSosActive] = useState(false);

  const [isSearching, setIsSearching] = useState(false);
  const [showAllStocks, setShowAllStocks] = useState(false);

  useEffect(() => {
    loadStocks();
  }, []);

  const loadStocks = async () => {
    const s = await API.getBloodStocks();
    setBloodStocks(s);
  };

  const handleSearch = async () => {
    setIsSearching(true);
    setSearchResults([]); 
    await new Promise(resolve => setTimeout(resolve, 2000));
    try {
      const results = await findDonorsWithAI(bloodType, city);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSOS = async () => {
    setSosActive(!sosActive);
    if (!sosActive) {
      const currentUser = JSON.parse(localStorage.getItem('lifeflow_current_user') || '{}');
      const req: DonationRequest = {
        id: `sos-${Date.now()}`,
        donorName: currentUser.name || 'Anonymous User',
        bloodType: currentUser.bloodType || 'Unknown',
        status: 'Pending',
        date: new Date().toISOString().split('T')[0],
        urgency: 'Critical',
        hospital: 'EMERGENCY BROADCAST'
      };
      await API.addDonationRequest(req);
      alert("EMERGENCY: SOS broadcast sent to Admin and all nearby donors.");
    }
  };

  const submitFeedback = async () => {
    const msg = prompt("Enter your feedback for the Admin:");
    if (msg) {
      const currentUser = JSON.parse(localStorage.getItem('lifeflow_current_user') || '{}');
      const f: Feedback = {
        id: `f-${Date.now()}`,
        userId: currentUser.id,
        userRole: currentUser.role,
        message: msg,
        date: new Date().toISOString().split('T')[0]
      };
      await API.addFeedback(f);
      alert("Feedback received.");
    }
  };

  const displayedStocks = showAllStocks ? bloodStocks : bloodStocks.slice(0, 3);

  return (
    <div className="space-y-10 pb-12">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className={`rounded-3xl p-8 shadow-xl transition-all duration-500 flex flex-col justify-between relative overflow-hidden ${sosActive ? 'bg-red-600 text-white' : 'bg-white text-gray-800 border border-gray-100'}`}>
          <div className="relative z-10">
             <div className="flex items-center gap-3 mb-4">
               <div className={`p-3 rounded-full ${sosActive ? 'bg-white/20' : 'bg-red-50 text-red-600'}`}>
                 <AlertTriangle size={24} />
               </div>
               <h2 className="text-2xl font-bold">Emergency SOS</h2>
             </div>
             <p className={`mb-6 text-lg ${sosActive ? 'text-red-100' : 'text-gray-500'}`}>
               {sosActive ? 'Broadcasting urgent need to all donors nearby...' : 'Instantly notify all donors in your area for critical blood needs.'}
             </p>
             <Button onClick={handleSOS} className={`w-full py-4 text-lg rounded-xl border-none ${sosActive ? 'bg-white text-red-600' : 'bg-red-600 text-white shadow-lg shadow-red-500/30'}`}>
               {sosActive ? 'Cancel Broadcast' : 'Broadcast Alert'}
             </Button>
          </div>
          {sosActive && <div className="absolute inset-0 bg-red-600 animate-pulse"></div>}
        </div>
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl shadow-lg border border-gray-100">
           <div className="flex justify-between items-center mb-8">
             <h2 className="text-xl font-bold flex items-center gap-2"><Activity className="text-blood-600"/> Live Stock Levels</h2>
             <Button variant="outline" className="text-xs" onClick={() => setShowAllStocks(!showAllStocks)}>
               {showAllStocks ? 'Show Less' : 'View All'}
             </Button>
           </div>
           <div className="space-y-6 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {displayedStocks.map(stock => (
                <div key={stock.id} className="cursor-pointer hover:bg-gray-50 p-2 rounded-xl transition-colors">
                  <div className="flex justify-between text-sm font-bold mb-2">
                    <span className="flex items-center gap-2">
                      <span className="w-6 h-6 rounded bg-gray-100 flex items-center justify-center text-xs">{stock.bloodType}</span>
                      <span>{stock.hospitalName}</span>
                    </span>
                    <span className={stock.units < 10 ? 'text-red-500' : 'text-green-500'}>{stock.units} Units</span>
                  </div>
                  <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${stock.units < 10 ? 'bg-red-500' : 'bg-green-500'}`} style={{ width: `${Math.min((stock.units / stock.maxCapacity) * 100, 100)}%` }}></div>
                  </div>
                </div>
              ))}
           </div>
        </div>
      </div>
      <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
        <div className="p-8 border-b border-gray-100 bg-gray-50/50">
           <h2 className="text-2xl font-bold mb-6">Find a Donor</h2>
           <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-1 relative">
                 <Droplet className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20}/>
                 <select value={bloodType} onChange={(e) => setBloodType(e.target.value)} className="w-full pl-12 pr-4 py-4 rounded-xl border-none bg-white shadow-sm appearance-none">
                    <option value="All">All Blood Types</option>
                    <option value="A+">A+</option><option value="O+">O+</option>
                  </select>
              </div>
              <div className="flex-[2] relative">
                 <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20}/>
                 <input type="text" placeholder="Enter City (e.g. New York)" value={city} onChange={(e) => setCity(e.target.value)} className="w-full pl-12 pr-4 py-4 rounded-xl border-none bg-white shadow-sm" />
              </div>
              <Button onClick={handleSearch} disabled={isSearching} className="px-8 py-4 rounded-xl min-w-[160px]">{isSearching ? 'Searching...' : 'Search Donors'}</Button>
           </div>
        </div>
        <div className="p-8 bg-gray-50 min-h-[300px]">
           {isSearching ? (
              <div className="flex flex-col items-center justify-center h-[200px] space-y-4">
                <div className="w-12 h-12 border-4 border-blood-200 border-t-blood-600 rounded-full animate-spin"></div>
                <p className="text-gray-500 font-medium animate-pulse">Scanning network...</p>
              </div>
           ) : searchResults.length > 0 ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
               {searchResults.map(donor => (
                 <div key={donor.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <div className="flex items-center gap-4 mb-4">
                       <div className="w-14 h-14 rounded-full bg-blood-100 flex items-center justify-center text-blood-700 font-bold text-lg">{donor.bloodType}</div>
                       <div className="flex-1"><h3 className="font-bold text-gray-800">{donor.name}</h3><p className="text-xs text-gray-500">{donor.location}</p></div>
                    </div>
                    <Button className="w-full text-sm" onClick={() => alert("Request Sent")}>Request</Button>
                 </div>
               ))}
             </div>
           ) : <p className="text-center py-12 text-gray-400">Search to see real-time donors.</p>}
        </div>
      </div>
      <div className="bg-gray-900 text-white p-8 rounded-3xl flex justify-between items-center">
        <div><h3 className="text-xl font-bold">Need assistance?</h3><p className="text-gray-400">Send feedback to the system administrator.</p></div>
        <Button onClick={submitFeedback} className="bg-white text-gray-900">Contact Admin</Button>
      </div>
    </div>
  );
};

