               <tr>
                  <th className="p-4 font-bold text-gray-600">User</th>
                  <th className="p-4 font-bold text-gray-600">Role</th>
                  <th className="p-4 font-bold text-gray-600">Performance</th>
                  <th className="p-4 font-bold text-gray-600">Status</th>
                  <th className="p-4 font-bold text-gray-600 text-right">Actions</th>
               </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
               {users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.role.toLowerCase().includes(searchQuery.toLowerCase())).map(user => (
                  <tr key={user.id} className="hover:bg-gray-50 transition-colors">
                     <td className="p-4">
                        <div className="flex items-center gap-3">
                           <div className="w-10 h-10 rounded-full bg-gray-200 flex items-center justify-center font-bold text-gray-500">
                              {user.name.charAt(0)}
                           </div>
                           <div>
                              <p className="font-bold text-gray-900">{user.name}</p>
                              <p className="text-xs text-gray-500">{user.location || 'Unknown'}</p>
                           </div>
                        </div>
                     </td>
                     <td className="p-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${user.role === 'DONOR' ? 'bg-red-100 text-red-700' : user.role === 'ADMIN' ? 'bg-gray-800 text-white' : 'bg-blue-100 text-blue-700'}`}>
                           {user.role}
                        </span>
                     </td>
                     <td className="p-4">
                        {user.role === 'DONOR' ? (
                           <div className="flex items-center gap-2">
                              <div className="flex flex-col">
                                 <span className="text-xs font-bold text-blood-600">Lvl {user.level || 1}</span>
                                 <span className="text-xs text-gray-400">{user.xp || 0} XP</span>
                              </div>
                              <div className="w-16 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                                 <div className="h-full bg-blood-500" style={{ width: `${(user.xp || 0) % 100}%` }}></div>
                              </div>
                           </div>
                        ) : (
                           <span className="text-gray-400 text-xs">-</span>
                        )}
                     </td>
                     <td className="p-4">
                        {user.status === 'Blocked' ? (
                           <span className="px-2 py-1 bg-red-100 text-red-600 rounded text-xs font-bold flex items-center gap-1 w-fit"><Ban size={12}/> Blocked</span>
                        ) : (
                           <span className="px-2 py-1 bg-green-100 text-green-600 rounded text-xs font-bold flex items-center gap-1 w-fit"><CheckCircle size={12}/> Active</span>
                        )}
                     </td>
                     <td className="p-4 text-right">
                        <div className="flex justify-end gap-2">
                           {user.role === 'DONOR' && (
                              <>
                                 <button onClick={() => handlePromoteUser(user.id, user.name)} className="p-2 hover:bg-yellow-50 text-yellow-600 rounded-lg" title="Promote"><Trophy size={16}/></button>
                                 <button onClick={() => handleIssueKey(user.id, user.name)} className="p-2 hover:bg-blue-50 text-blue-600 rounded-lg" title="Issue Key"><Key size={16}/></button>
                              </>
                           )}
                           <button onClick={() => handleBlockUser(user.id, user.name)} className={`p-2 rounded-lg ${user.status === 'Blocked' ? 'hover:bg-green-50 text-green-600' : 'hover:bg-red-50 text-red-600'}`}>
                              {user.status === 'Blocked' ? <CheckCircle size={16}/> : <Ban size={16}/>}
                           </button>
                        </div>
                     </td>
                  </tr>
               ))}
            </tbody>
         </table>
      </div>
    </div>
  );

  const renderFeedback = () => (
    <div className="space-y-6 animate-fade-in-up">
       <div className="bg-white p-6 rounded-3xl border border-gray-100 flex justify-between items-center">
          <h2 className="text-2xl font-bold text-gray-800">Feedback Inbox</h2>
          <span className="bg-blood-100 text-blood-700 px-4 py-1 rounded-full text-xs font-bold">{feedbacks.length} Messages</span>
       </div>
       <div className="grid grid-cols-1 gap-6">
          {feedbacks.length > 0 ? feedbacks.map(f => (
             <div key={f.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:border-blood-200 transition-all">
                <div className="flex justify-between items-start mb-4">
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-gray-200 rounded-full flex items-center justify-center font-bold text-gray-500">
                         {f.userRole.charAt(0)}
                      </div>
                      <div>
                        <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest ${f.userRole === 'DONOR' ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-700'}`}>
                           {f.userRole}
                        </span>
                        <p className="text-xs text-gray-400 mt-0.5">{f.date}</p>
                      </div>
                   </div>
                   {!f.reply && replyingTo !== f.id && (
                     <Button variant="outline" className="text-xs h-8 px-4 gap-2 font-black uppercase tracking-widest" onClick={() => setReplyingTo(f.id)}>
                        <MessageSquare size={12} /> Reply
                     </Button>
                   )}
                </div>

                <div className="bg-gray-50 p-4 rounded-xl border border-gray-100 mb-4">
                  <p className="text-gray-800 font-medium italic">"{f.message}"</p>
                </div>

                {f.reply ? (
                  <div className="bg-blood-50 p-4 rounded-xl border border-blood-100 border-l-4 border-l-blood-600">
                    <p className="text-[10px] font-black text-blood-600 uppercase tracking-[0.2em] mb-1">Administrative Reply</p>
                    <p className="text-blood-900 text-sm font-bold">"{f.reply}"</p>
                  </div>
                ) : replyingTo === f.id ? (
                  <div className="mt-4 space-y-3 animate-fade-in-up">
                    <textarea 
                      value={replyText}
                      onChange={(e) => setReplyText(e.target.value)}
                      placeholder="Type your official response here..."
                      className="w-full h-24 p-4 bg-white border border-blood-200 rounded-xl outline-none focus:ring-2 focus:ring-blood-500 font-medium text-sm transition-all"
                    />
                    <div className="flex justify-end gap-2">
                       <Button variant="outline" className="text-xs px-4" onClick={() => { setReplyingTo(null); setReplyText(''); }}>
                          <X size={14} className="mr-1"/> Cancel
                       </Button>
                       <Button 
                        onClick={() => submitReply(f.id)} 
                        isLoading={isSubmittingReply}
                        disabled={!replyText.trim()}
                        className="text-xs px-6 gap-2 font-black uppercase tracking-widest"
                       >
                          <Send size={14} /> Send Reply
                       </Button>
                    </div>
                  </div>
                ) : (
                  <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest italic">Awaiting response from Control Center...</p>
                )}
             </div>
          )) : (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
              <MessageSquare className="mx-auto text-gray-200 mb-4" size={48} />
              <p className="text-gray-400 font-bold uppercase tracking-widest">No feedback received in this cycle.</p>
            </div>
          )}
       </div>
    </div>
  );

  const renderSearch = () => (
    <div className="space-y-6 animate-fade-in-up">
       <div className="bg-white p-8 rounded-3xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center gap-2"><Search className="text-blood-600"/> Admin Emergency Search</h2>
          <div className="flex flex-col md:flex-row gap-4">
              <select value={adminSearchType} onChange={(e) => setAdminSearchType(e.target.value)} className="p-4 rounded-xl bg-gray-50 border-none font-bold">
                <option value="All">All Types</option>
                <option value="A+">A+</option><option value="O+">O+</option>
              </select>
              <input type="text" placeholder="City or Region" value={adminSearchCity} onChange={(e) => setAdminSearchCity(e.target.value)} className="flex-1 p-4 rounded-xl bg-gray-50 border-none font-bold" />
              <Button onClick={handleAdminSearch} disabled={isSearching} className="px-8 font-black uppercase tracking-widest">{isSearching ? 'Scanning...' : 'Locate'}</Button>
          </div>
       </div>
       {isSearching ? (
          <div className="text-center py-12">
             <div className="w-12 h-12 border-4 border-blood-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
             <p className="text-gray-500 font-bold">Scanning network...</p>
          </div>
       ) : searchResults.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             {searchResults.map(res => (
               <div key={res.id} className="bg-white p-6 rounded-2xl shadow-sm border-l-4 border-l-blood-600 flex items-start gap-4">
                  <div className="w-12 h-12 bg-blood-100 text-blood-700 rounded-full flex items-center justify-center font-bold text-lg">{res.bloodType}</div>
                  <div className="flex-1">
                     <h4 className="font-bold text-gray-900 text-lg">{res.name}</h4>
                     <p className="text-gray-500 flex items-center gap-1 text-sm"><MapPin size={14}/> {res.location}</p>
                     <div className="mt-3 flex gap-2"><Button className="text-xs h-auto py-1 px-4">Secure Contact</Button></div>
                  </div>
               </div>
             ))}
          </div>
       ) : null}
    </div>
  );

  return (
    <div className="space-y-8 pb-12">
      <div className="bg-white p-2 rounded-2xl shadow-sm border border-gray-100 inline-flex flex-wrap gap-2 w-full md:w-auto">
         <button onClick={() => setActiveTab('dashboard')} className={`px-6 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'dashboard' ? 'bg-gray-900 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>Dashboard</button>
         <button onClick={() => setActiveTab('users')} className={`px-6 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>User Management</button>
         <button onClick={() => setActiveTab('feedback')} className={`px-6 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'feedback' ? 'bg-orange-500 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>Feedback Inbox</button>
         <button onClick={() => setActiveTab('search')} className={`px-6 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'search' ? 'bg-blood-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>Blood Search</button>
      </div>
      <div className="min-h-[500px]">
         {activeTab === 'dashboard' && renderDashboard()}
         {activeTab === 'users' && renderUsers()}
         {activeTab === 'feedback' && renderFeedback()}
         {activeTab === 'search' && renderSearch()}
      </div>
    </div>
  );
};

export enum UserRole {
  ADMIN = 'ADMIN',
  DONOR = 'DONOR',
  USER = 'USER', // Recipient
  GUEST = 'GUEST'
}

export interface User {
  id: string;
  username: string;
  role: UserRole;
  name: string;
  bloodType?: string; // For donors and users
  location?: string;
  isVerified?: boolean; // Verified by special key (for donors)
  avatarUrl?: string;
  joinDate?: string;
  phone?: string; // Added for contact details
  email?: string; // Added
  address?: string; // Added
  level?: number; // Gamification
  xp?: number; // Gamification
  status?: 'Active' | 'Blocked'; // New: for admin control
}

export interface BloodStock {
  id: string;
  bloodType: string;
  units: number;
  maxCapacity: number; // Added for visual progress bars
  hospitalName: string;
  city: string;
  contactNumber: string;
}

export interface DonationRequest {
  id: string;
  donorName: string; // Used for Patient/Requester Name too
  bloodType: string;
  status: 'Pending' | 'Approved' | 'Completed' | 'Rejected';
  date: string;
  urgency: 'Low' | 'Medium' | 'Critical';
  hospital?: string;
  location?: string; // New: City/Region
  phone?: string; // New: Contact Phone
  type?: 'Donation' | 'Request'; // New: To distinguish
}

export interface BloodRequest {
  id: string;
  requesterName: string;
  requesterType: 'Hospital' | 'User';
  bloodType: string;
  units: number;
  urgency: 'Normal' | 'High' | 'Critical';
  location: string;
  contact: string;
  distance: string;
  date: string;
}

export interface DonorCertificate {
  id: string;
  donorId: string;
  date: string;
  hospitalName: string;
  imageUrl: string; // In real app, this would be a URL. Mocking with string.
}

export interface Feedback {
  id: string;
  userId: string;
  userRole: string;
  message: string;
  date: string;
  reply?: string; // Added for admin responses
}

export interface Hospital {
  id: string;
  name: string;
  city: string;
  address: string;
  phone: string;
  email: string;
  coordinates?: { lat: number; lng: number };
}

export interface EmergencyKey {
  id: string;
  code: string;
  type: 'Gold' | 'Platinum';
  usesRemaining: number;
  issuedDate: string;
  status: 'Active' | 'Expired';
}

export interface SecurityLog {
  id: string;
  severity: 'Low' | 'Medium' | 'High' | 'Critical';
  message: string;
  timestamp: string;
  user?: string;
}

// New Types for "Big" Features
export interface Campaign {
  id: string;
  title: string;
  description: string;
  date: string;
  location: string;
  imageUrl: string;
  attendees: number;
}

export interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string; // Emoji or Lucide icon name
  earnedDate?: string;
  locked: boolean;
}

export interface Appointment {
  id: string;
  hospitalName: string;
  date: string;
  time: string;
  status: 'Scheduled' | 'Completed';
}

import React, { useState, useEffect } from 'react';
import { Search, MapPin, Droplet, Phone, MessageCircle, Activity, Users, Info, Send, Clock, CheckCircle2, MessageSquareText, ShieldCheck, ArrowLeft, PlusCircle, AlertCircle, Building2 } from 'lucide-react';
import { User, Feedback, UserRole, DonationRequest } from '../types';
import { API } from '../services/api';
import { findDonorsWithAI } from '../services/geminiService';
import { Button } from './Button';

type UserPanelView = 'search' | 'register_request';

export const UserPanel: React.FC = () => {
  const [activeView, setActiveView] = useState<UserPanelView>('search');
  const [bloodType, setBloodType] = useState('All');
  const [city, setCity] = useState('');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [allDonors, setAllDonors] = useState<User[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [isLoadingDonors, setIsLoadingDonors] = useState(true);

  // Blood Request Form State
  const [requestForm, setRequestForm] = useState({
    patientName: '',
    bloodType: 'O+',
    units: 1,
    hospital: '',
    city: '',
    phone: '',
    urgency: 'Medium' as 'Low' | 'Medium' | 'Critical'
  });
  const [isSubmittingRequest, setIsSubmittingRequest] = useState(false);

  // Feedback states
  const [feedbackText, setFeedbackText] = useState('');
  const [isSendingFeedback, setIsSendingFeedback] = useState(false);
  const [userFeedbacks, setUserFeedbacks] = useState<Feedback[]>([]);

  const currentUser = JSON.parse(localStorage.getItem('lifeflow_current_user') || '{}');

  useEffect(() => {
    loadDonors();
    loadMyFeedbacks();
  }, []);

  const loadDonors = async () => {
    setIsLoadingDonors(true);
    try {
      const users = await API.getUsers();
      const donors = users.filter(u => u.role === UserRole.DONOR && u.status !== 'Blocked');
      setAllDonors(donors);
    } catch (error) {
      console.error("Failed to load donors", error);
    } finally {
      setIsLoadingDonors(false);
    }
  };

  const loadMyFeedbacks = async () => {
    try {
      const allFeedbacks = await API.getFeedbacks();
      setUserFeedbacks(allFeedbacks.filter(f => f.userId === currentUser.id));
    } catch (error) {
      console.error("Failed to load feedbacks", error);
    }
  };

  const handleSearch = async () => {
    setIsSearching(true);
    setHasSearched(true);
    setSearchResults([]); 
    await new Promise(resolve => setTimeout(resolve, 2000));
    try {
      const results = await findDonorsWithAI(bloodType, city);
      setSearchResults(results);
    } catch (error) {
      console.error("Search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleRequestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmittingRequest(true);
    try {
      const req: DonationRequest = {
        id: `req-${Date.now()}`,
        donorName: requestForm.patientName,
        bloodType: requestForm.bloodType,
        status: 'Pending',
        date: new Date().toLocaleDateString(),
        urgency: requestForm.urgency,
        hospital: requestForm.hospital,
        location: requestForm.city,
        phone: requestForm.phone,
        type: 'Request'
      };
      await API.addDonationRequest(req);
      alert("Emergency Request Registered. Administrators have been notified.");
      setActiveView('search');
      setRequestForm({
        patientName: '',
        bloodType: 'O+',
        units: 1,
        hospital: '',
        city: '',
        phone: '',
        urgency: 'Medium'
      });
    } catch (err) {
      alert("Failed to register request.");
    } finally {
      setIsSubmittingRequest(false);
    }
  };

  const handleSubmitFeedback = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!feedbackText.trim()) return;

    setIsSendingFeedback(true);
    try {
      const f: Feedback = {
        id: `f-${Date.now()}`,
        userId: currentUser.id,
        userRole: currentUser.role,
        message: feedbackText.trim(),
        date: new Date().toLocaleString()
      };
      await API.addFeedback(f);
      setFeedbackText('');
      await loadMyFeedbacks();
      alert("Message transmitted to Admin.");
    } catch (error) {
      alert("Failed to send message.");
    } finally {
      setIsSendingFeedback(false);
    }
  };

  const renderSearchEngine = () => (
    <div className="space-y-10">
      {/* Search Bar Container */}
      <div className="bg-white rounded-[2rem] shadow-xl border border-gray-100 overflow-hidden">
        <div className="p-8 border-b border-gray-100 bg-gray-50/30">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black text-gray-900 tracking-tight uppercase flex items-center gap-3">
                <Search className="text-blood-600" /> Network Search Engine
              </h2>
              <Button 
                variant="outline" 
                onClick={() => setActiveView('register_request')}
                className="text-xs h-auto py-2 px-4 gap-2 border-blood-200 text-blood-600 font-black uppercase tracking-widest"
              >
                <PlusCircle size={14} /> Manual Registration
              </Button>
           </div>
           <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-1 relative">
                 <Droplet className="absolute left-4 top-1/2 -translate-y-1/2 text-blood-600" size={20}/>
                 <select value={bloodType} onChange={(e) => setBloodType(e.target.value)} className="w-full pl-12 pr-4 py-4 rounded-2xl border-none bg-white shadow-xl focus:ring-2 focus:ring-blood-500 appearance-none font-bold text-gray-800">
                    <option value="All">All Blood Types</option>
                    <option value="A+">A+</option><option value="A-">A-</option>
                    <option value="B+">B+</option><option value="B-">B-</option>
                    <option value="O+">O+</option><option value="O-">O-</option>
                    <option value="AB+">AB+</option><option value="AB-">AB-</option>
                  </select>
              </div>
              <div className="flex-[2] relative">
                 <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-blood-600" size={20}/>
                 <input type="text" placeholder="Enter City (e.g. New York, London)" value={city} onChange={(e) => setCity(e.target.value)} className="w-full pl-12 pr-4 py-4 rounded-2xl border-none bg-white shadow-xl focus:ring-2 focus:ring-blood-500 font-bold" />
              </div>
              <Button onClick={handleSearch} disabled={isSearching} className="px-10 py-4 rounded-2xl shadow-2xl shadow-blood-500/30 min-w-[180px] font-black uppercase tracking-widest">
                {isSearching ? 'Scanning...' : 'Search Network'}
              </Button>
           </div>
        </div>

        <div className="p-8 bg-gray-50/50 min-h-[350px]">
           {isSearching ? (
              <div className="flex flex-col items-center justify-center h-[250px] space-y-4">
                <div className="w-14 h-14 border-4 border-blood-200 border-t-blood-600 rounded-full animate-spin"></div>
                <p className="text-gray-500 font-black text-xs tracking-[0.2em] animate-pulse uppercase">Syncing with Gemini AI Cluster...</p>
              </div>
           ) : searchResults.length > 0 ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 animate-fade-in-up">
               {searchResults.map(donor => (
                 <div key={donor.id} className="bg-white p-6 rounded-[2rem] shadow-sm hover:shadow-2xl transition-all border border-gray-100 group relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                      <Droplet size={60} />
                    </div>
                    <div className="flex items-center gap-4 mb-6">
                       <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-blood-100 to-blood-200 flex items-center justify-center text-blood-700 font-black text-xl shadow-inner">
                          {donor.bloodType}
                       </div>
                       <div className="flex-1">
                          <h3 className="font-black text-gray-900 text-lg">{donor.name}</h3>
                          <p className="text-xs text-gray-400 font-bold uppercase tracking-widest flex items-center gap-1">
                            <MapPin size={10} className="text-blood-400" /> {donor.location}
                          </p>
                       </div>
                    </div>
                    <div className="flex gap-2">
                       <Button className="flex-1 text-xs font-black uppercase tracking-widest h-11 rounded-xl" onClick={() => alert("Urgent Request Logged")}>Send Request</Button>
                       <button className="w-11 h-11 bg-gray-50 rounded-xl flex items-center justify-center text-gray-400 hover:bg-blood-50 hover:text-blood-600 transition-colors shadow-sm">
                         <MessageCircle size={20} />
                       </button>
                    </div>
                 </div>
               ))}
             </div>
           ) : hasSearched ? (
             <div className="flex flex-col items-center justify-center h-[250px] text-center max-w-md mx-auto space-y-6">
                <div className="w-20 h-20 bg-orange-50 text-orange-500 rounded-full flex items-center justify-center border-2 border-orange-100 border-dashed">
                  <AlertCircle size={40} />
                </div>
                <div>
                  <h3 className="text-xl font-black text-gray-900 uppercase">No Immediate Matches</h3>
                  <p className="text-sm text-gray-500 font-medium mt-2">We couldn't find any donors matching your criteria right now. You should register a public emergency request so admins can manually source blood for you.</p>
                </div>
                <Button onClick={() => setActiveView('register_request')} className="px-8 py-3 rounded-xl gap-2 font-black uppercase tracking-widest">
                  <PlusCircle size={18} /> Register Emergency Request
                </Button>
             </div>
           ) : (
             <div className="flex flex-col items-center justify-center h-[250px] text-gray-300">
                <Info size={48} className="mb-4 opacity-20" />
                <p className="font-black uppercase tracking-widest text-sm">Enter search criteria to initialize network scan</p>
             </div>
           )}
        </div>
      </div>
    </div>
  );

  const renderRegisterRequest = () => (
    <div className="max-w-4xl mx-auto animate-fade-in-up">
      <div className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-100 overflow-hidden">
        <div className="bg-blood-600 p-10 text-white flex justify-between items-start">
           <div>
