import React, { useState, useEffect } from 'react';
import { Users, Activity, Key, MessageSquare, ShieldCheck, TrendingUp, BarChart2, Ban, CheckCircle, Trophy, Search, MapPin, RefreshCcw, Send, X, Phone, Building2 } from 'lucide-react';
import { User, DonationRequest, Feedback, BloodStock, SecurityLog } from '../types';
import { API } from '../services/api';
