import { User, UserRole, BloodStock, DonationRequest, Appointment, Feedback, SecurityLog, BloodRequest } from "../types";
import { DB } from "./db";

const delay = (ms: number = 600) => new Promise(resolve => setTimeout(resolve, ms));

export const API = {
  // --- AUTH ---
  login: async (username: string, password: string, role: UserRole): Promise<User | null> => {
    await delay(800);
    const users = DB.getUsers();
    const user = users.find(u => 
      u.username.toLowerCase() === username.toLowerCase() && 
      (u as any).password === password &&
      u.role === role
    );
    if (user) {
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Low', message: `${role} Login: ${user.username}`, timestamp: new Date().toLocaleString() });
    }
    return user || null;
  },

  register: async (userData: Partial<User & { password?: string }>): Promise<User> => {
    await delay(1000);
    const users = DB.getUsers();
    if (users.some(u => u.username.toLowerCase() === (userData.username || '').toLowerCase())) {
      throw new Error("Username already taken.");
    }

    const newUser: User = {
      id: `u-${Date.now()}`,
      username: userData.username || '',
      name: userData.name || userData.username || '',
      role: userData.role || UserRole.USER,
      bloodType: userData.bloodType,
      location: userData.location,
      phone: userData.phone,
      email: userData.email,
      address: userData.address,
      joinDate: new Date().toISOString().split('T')[0],
      status: 'Active',
      level: 1,
      xp: 0
    };

    (newUser as any).password = userData.password;
    users.push(newUser);
    DB.saveUsers(users);
    DB.addLog({ id: `log-${Date.now()}`, severity: 'Medium', message: `New ${newUser.role} registered: ${newUser.username}`, timestamp: new Date().toLocaleString() });
    return newUser;
  },

  // --- DATA FETCHING ---
  getUsers: async (): Promise<User[]> => {
    await delay(300);
    return DB.getUsers();
  },

  getBloodStocks: async (): Promise<BloodStock[]> => {
    await delay(400);
    return DB.getStocks();
  },

  getDonationRequests: async (): Promise<DonationRequest[]> => {
    await delay(300);
    return DB.getRequests();
  },

  getFeedbacks: async (): Promise<Feedback[]> => {
    await delay(200);
    return DB.getFeedbacks();
  },

  getSecurityLogs: async (): Promise<SecurityLog[]> => {
    await delay(200);
    return DB.getLogs();
  },

  // --- ACTIONS ---
  addDonationRequest: async (req: DonationRequest): Promise<void> => {
    await delay(500);
    const requests = DB.getRequests();
    requests.unshift(req);
    DB.saveRequests(requests);
    DB.addLog({ id: `log-${Date.now()}`, severity: 'High', message: `New Request: ${req.bloodType} from ${req.donorName}`, timestamp: new Date().toLocaleString() });
  },

  updateDonationRequestStatus: async (requestId: string, status: 'Pending' | 'Approved' | 'Completed' | 'Rejected'): Promise<void> => {
    await delay(400);
    const requests = DB.getRequests();
    const index = requests.findIndex(r => r.id === requestId);
    if (index !== -1) {
      requests[index].status = status;
      DB.saveRequests(requests);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Medium', message: `Request ${requestId} status updated to ${status}`, timestamp: new Date().toLocaleString() });
    }
  },

  addFeedback: async (feedback: Feedback): Promise<void> => {
    await delay(400);
    const feedbacks = DB.getFeedbacks();
    feedbacks.unshift(feedback);
    DB.saveFeedbacks(feedbacks);
  },

  replyToFeedback: async (feedbackId: string, reply: string): Promise<void> => {
    await delay(400);
    const feedbacks = DB.getFeedbacks();
    const index = feedbacks.findIndex(f => f.id === feedbackId);
    if (index !== -1) {
      feedbacks[index].reply = reply;
      DB.saveFeedbacks(feedbacks);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Low', message: `Admin replied to feedback ${feedbackId}`, timestamp: new Date().toLocaleString() });
    }
  },

  toggleUserStatus: async (userId: string): Promise<string | null> => {
    await delay(400);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user) {
      user.status = user.status === 'Active' ? 'Blocked' : 'Active';
      DB.saveUsers(users);
      DB.addLog({ id: `log-${Date.now()}`, severity: 'Critical', message: `User status updated: ${user.username} (${user.status})`, timestamp: new Date().toLocaleString() });
      return user.status;
    }
    return null;
  },

  promoteDonor: async (userId: string): Promise<number | null> => {
    await delay(500);
    const users = DB.getUsers();
    const user = users.find(u => u.id === userId);
    if (user && user.role === UserRole.DONOR) {
      user.level = (user.level || 1) + 1;
      user.xp = (user.xp || 0) + 100;
      DB.saveUsers(users);
      return user.level;
    }
    return null;
  },

  issueEmergencyKey: async (userId: string): Promise<string> => {
    await delay(500);
    const key = `GRANT-${Math.floor(1000 + Math.random() * 8999)}`;
    DB.addLog({ id: `log-${Date.now()}`, severity: 'High', message: `Emergency Key issued for user ${userId}`, timestamp: new Date().toLocaleString() });
    return key;
  },

  getBloodNeeds: async (): Promise<BloodRequest[]> => {
    await delay(300);
    // Hardcoded feed for UI demo, but could be DB-backed
    return [
      { id: 'req1', requesterName: 'City General', requesterType: 'Hospital', bloodType: 'O+', units: 5, urgency: 'Critical', location: 'New York', contact: '555-0101', distance: '2km', date: '2023-10-28' }
    ];
  },

  getAppointments: async (): Promise<Appointment[]> => {
    return [];
  },

  scheduleAppointment: async (app: Appointment): Promise<void> => {
    await delay(400);
  }
};

import React, { useState, useEffect } from 'react';
import { Users, Activity, Key, MessageSquare, ShieldCheck, TrendingUp, BarChart2, Ban, CheckCircle, Trophy, Search, MapPin, RefreshCcw, Send, X, Phone, Building2, CheckCircle2 } from 'lucide-react';
import { User, DonationRequest, Feedback, BloodStock, SecurityLog } from '../types';
import { API } from '../services/api';
import { Button } from './Button';
import { findDonorsWithAI } from '../services/geminiService';

type AdminTab = 'dashboard' | 'users' | 'feedback' | 'search';

export const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('dashboard');

  // Data States
  const [users, setUsers] = useState<User[]>([]);
  const [requests, setRequests] = useState<DonationRequest[]>([]);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);
  const [stocks, setStocks] = useState<BloodStock[]>([]);
  const [logs, setLogs] = useState<SecurityLog[]>([]);
  const [generatedKey, setGeneratedKey] = useState<string>('');
  const [isRefreshing, setIsRefreshing] = useState(false);

  // UI States for Feedback
  const [replyingTo, setReplyingTo] = useState<string | null>(null);
  const [replyText, setReplyText] = useState('');
  const [isSubmittingReply, setIsSubmittingReply] = useState(false);

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [adminSearchCity, setAdminSearchCity] = useState('');
  const [adminSearchType, setAdminSearchType] = useState('All');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = async () => {
    setIsRefreshing(true);
    try {
      const [u, r, f, s, l] = await Promise.all([
        API.getUsers(),
        API.getDonationRequests(),
        API.getFeedbacks(),
        API.getBloodStocks(),
        API.getSecurityLogs()
      ]);
      setUsers(u);
      setRequests(r);
      setFeedbacks(f);
      setStocks(s);
      setLogs(l);
    } catch (e) {
      console.error("Failed to sync admin data", e);
    } finally {
      setIsRefreshing(false);
    }
  };

  const handleStatusUpdate = async (requestId: string, newStatus: 'Pending' | 'Approved' | 'Completed' | 'Rejected') => {
    try {
      await API.updateDonationRequestStatus(requestId, newStatus);
      await refreshData();
    } catch (e) {
      alert("Failed to update status");
    }
  };

  const generateKey = () => {
    setGeneratedKey(`BLOOD-KEY-${Math.floor(1000 + Math.random() * 9000)}`);
  };

  const handleBlockUser = async (id: string, name: string) => {
    if (confirm(`Are you sure you want to toggle BLOCK status for ${name}?`)) {
      await API.toggleUserStatus(id);
      refreshData();
    }
  };

  const handlePromoteUser = async (id: string, name: string) => {
    const newLevel = await API.promoteDonor(id);
    if (newLevel) {
      refreshData();
    }
  };

  const handleIssueKey = async (id: string, name: string) => {
    const key = await API.issueEmergencyKey(id);
    alert(`Emergency Key Issued to ${name}: ${key}`);
  };

  const submitReply = async (fId: string) => {
    if (!replyText.trim()) return;
    setIsSubmittingReply(true);
    try {
      await API.replyToFeedback(fId, replyText.trim());
      setReplyText('');
      setReplyingTo(null);
      await refreshData();
    } catch (error) {
      alert("Failed to send reply.");
    } finally {
      setIsSubmittingReply(false);
    }
  };

  const handleAdminSearch = async () => {
    setIsSearching(true);
    setSearchResults([]);
    await new Promise(resolve => setTimeout(resolve, 1500));
    try {
       const results = await findDonorsWithAI(adminSearchType, adminSearchCity);
       setSearchResults(results);
    } catch (e) {
       console.error("AI Search failed", e);
    } finally {
       setIsSearching(false);
    }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-fade-in-up">
      <div className="bg-gradient-to-r from-gray-900 to-gray-800 text-white p-8 rounded-3xl relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blood-600 rounded-full blur-3xl -mr-16 -mt-16 opacity-50"></div>
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-end gap-4">
          <div>
            <h1 className="text-3xl font-bold mb-2">System Overview</h1>
            <p className="text-gray-300">Security status: <span className="text-green-400 font-bold">Optimal</span>. All systems operational.</p>
          </div>
          <div className="flex gap-3">
            <Button variant="outline" isLoading={isRefreshing} className="border-white/20 text-white hover:bg-white/10 gap-2" onClick={refreshData}><RefreshCcw size={16}/> Sync Now</Button>
            <Button className="bg-blood-600 text-white border-none gap-2" onClick={() => setActiveTab('search')}><Search size={16}/> Urgent Search</Button>
          </div>
