           <h3 className="text-3xl font-bold text-gray-800">{users.length}</h3>
           <p className="text-gray-500 text-sm">Total Users</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
           <div className="p-3 bg-blood-50 text-blood-600 rounded-xl w-fit mb-4"><Activity size={24} /></div>
           <h3 className="text-3xl font-bold text-gray-800">{requests.filter(r => r.status === 'Pending').length}</h3>
           <p className="text-gray-500 text-sm">Active Tasks</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
           <div className="p-3 bg-purple-50 text-purple-600 rounded-xl w-fit mb-4"><BarChart2 size={24} /></div>
