                         req.urgency === 'Medium' ? 'text-orange-600 bg-orange-50' : 
                         'text-green-600 bg-green-50'
                       }`}>
                         {req.urgency}
                       </span>
                     </td>
                     <td className="py-5 text-right">
                       {req.status === 'Pending' ? (
                         <button 
                          onClick={() => handleStatusUpdate(req.id, 'Completed')}
