                         >
                           Pending
                         </button>
                       ) : (
                         <span className="px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-green-100 text-green-800 flex items-center justify-end gap-1 ml-auto w-fit">
                           <CheckCircle2 size={10} /> Done
                         </span>
