import { User, Achievement, Appointment, BloodRequest, DonorCertificate, EmergencyKey, DonationRequest } from '../types';
import { MockBackend } from '../services/mockBackend';
import { API } from '../services/api';
import { Button } from './Button';
import { getHealthTip, findDonorsWithAI } from '../services/geminiService';

interface DonorPanelProps {
  user: User;
}

type ActiveTab = 'dashboard' | 'requests' | 'certificates' | 'registration' | 'emergency';

export const DonorPanel: React.FC<DonorPanelProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<ActiveTab>('dashboard');

  // Data States
  const [specialKey, setSpecialKey] = useState('');
  const [isVerified, setIsVerified] = useState(user.isVerified);
  const [healthTip, setHealthTip] = useState('');
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [bloodRequests, setBloodRequests] = useState<BloodRequest[]>([]);
  const [certificates, setCertificates] = useState<DonorCertificate[]>([]);
  const [emergencyKeys, setEmergencyKeys] = useState<EmergencyKey[]>([]);
  const [allSystemRequests, setAllSystemRequests] = useState<DonationRequest[]>([]);

  // Real Stats derived from DB
  const [stats, setStats] = useState({ totalUnits: 0, livesImpacted: 0 });

  // Donation Form State
  const [donationForm, setDonationForm] = useState({
    username: user.username,
    city: user.location || '',
    contact: user.phone || '',
    bloodType: user.bloodType || 'O+',
    dateToGive: '',
    isMedicallyFit: false,
    units: 1
  });
  const [isSubmittingDonation, setIsSubmittingDonation] = useState(false);

  // Booking Modal State
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingRequest, setBookingRequest] = useState<BloodRequest | null>(null);
  const [bookingDate, setBookingDate] = useState('');
  const [bookingTime, setBookingTime] = useState('');

  useEffect(() => {
    loadData();
  }, [user.id]);

  const loadData = async () => {
    const [tip, systemRequests] = await Promise.all([
      getHealthTip('Donor'),
      API.getDonationRequests()
    ]);

    setHealthTip(tip);
    setAllSystemRequests(systemRequests);
    setAchievements(MockBackend.getAchievements());
    setAppointments(MockBackend.getAppointments());
    setBloodRequests(MockBackend.getBloodRequestsFeed());
    setCertificates(MockBackend.getMyCertificates(user.id));
    setEmergencyKeys(MockBackend.getEmergencyKeys());

    // Calculate real stats from completed donation requests
    const myCompletedDonations = systemRequests.filter(
      r => r.donorName === user.username && r.type === 'Donation' && r.status === 'Completed'
    );

    const units = myCompletedDonations.reduce((sum, r) => sum + (r.units || 0), 0);
    const impact = myCompletedDonations.reduce((sum, r) => sum + (r.livesImpacted || 0), 0);

    setStats({ totalUnits: units, livesImpacted: impact });
  };

  const handleVerify = () => {
    if (MockBackend.verifyDonorKey(specialKey)) {
      setIsVerified(true);
      alert("Verified successfully!");
    } else {
      alert("Invalid Key");
    }
  };

  const handleDonationSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!donationForm.isMedicallyFit) {
      alert("You must confirm medical fitness before donating.");
      return;
    }
    setIsSubmittingDonation(true);
    try {
      const reg: DonationRequest = {
        id: `don-${Date.now()}`,
        donorName: donationForm.username,
        bloodType: donationForm.bloodType,
        status: 'Pending',
        date: donationForm.dateToGive,
        urgency: 'Medium',
        location: donationForm.city,
        phone: donationForm.contact,
        type: 'Donation',
        isMedicallyFit: donationForm.isMedicallyFit,
        units: Number(donationForm.units)
      };
      await API.addDonationRequest(reg);
      alert("Donation registered! Thank you for your contribution.");
      setDonationForm(prev => ({ ...prev, dateToGive: '', isMedicallyFit: false, units: 1 }));
      await loadData();
    } catch (err) {
      alert("Failed to register donation.");
    } finally {
      setIsSubmittingDonation(false);
    }
  };

  const openBookingModal = (request: BloodRequest) => {
    setBookingRequest(request);
    setBookingDate(new Date().toISOString().split('T')[0]);
    setShowBookingModal(true);
  };

  const confirmBooking = () => {
    if (!bookingRequest || !bookingDate || !bookingTime) return;

    const newApp: Appointment = {
      id: Date.now().toString(),
      hospitalName: bookingRequest.requesterName,
      date: bookingDate,
      time: bookingTime,
      status: 'Scheduled'
    };
    MockBackend.scheduleAppointment(newApp);
    setAppointments([...appointments, newApp]);
    alert(`Donation scheduled for ${bookingRequest.requesterName} on ${bookingDate} at ${bookingTime}`);
    setShowBookingModal(false);
    setBookingRequest(null);
    setBookingTime('');
  };

  const handleFileUpload = () => {
    setTimeout(() => {
      const newCert: DonorCertificate = {
        id: Date.now().toString(),
        donorId: user.id,
        date: new Date().toISOString().split('T')[0],
        hospitalName: 'Community Hospital',
        imageUrl: 'placeholder'
      };
      MockBackend.addCertificate(newCert);
      setCertificates([...certificates, newCert]);
      alert("Certificate Uploaded Successfully!");
    }, 1000);
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-fade-in-up">
       <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
         <div className="lg:col-span-1 space-y-6">
            {/* Identity Card */}
            <div className="relative h-56 rounded-[2.5rem] overflow-hidden shadow-2xl">
               <div className="absolute inset-0 bg-gradient-to-br from-blood-600 to-blood-900"></div>
               <div className="relative z-10 p-8 flex flex-col justify-between h-full text-white">
                 <div className="flex justify-between items-start">
                   <div>
                     <p className="text-[10px] uppercase font-black tracking-[0.2em] opacity-70 mb-1">Official Member</p>
                     <h3 className="font-black text-2xl tracking-tight">{user.name}</h3>
                   </div>
                   {isVerified ? <div className="bg-green-500/20 p-2 rounded-xl"><CheckCircle size={20} className="text-green-400" /></div> : <Lock className="text-white/30" />}
                 </div>
                 <div className="flex items-end gap-6">
                   <div className="bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl p-3 text-center min-w-[70px]">
                     <p className="text-[9px] font-black opacity-60 uppercase mb-1">Group</p>
                     <p className="text-2xl font-black">{user.bloodType || 'O+'}</p>
                   </div>
                   <div>
                     <p className="text-xs font-bold opacity-80">{user.location || 'New York'}</p>
                     <p className="text-[10px] font-black uppercase tracking-widest opacity-40">Reg ID: {user.id.split('-')[1] || '0000'}</p>
                   </div>
                 </div>
               </div>
            </div>

            {/* Verification card if needed */}
            {!isVerified && (
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                <h3 className="font-black text-gray-900 mb-3 flex items-center gap-2 uppercase text-xs tracking-widest"><Lock size={16} className="text-yellow-500" /> Verify Account</h3>
                <div className="flex gap-2">
                  <input type="text" value={specialKey} onChange={(e) => setSpecialKey(e.target.value)} className="flex-1 bg-gray-50 border-none rounded-xl px-4 py-3 text-sm font-bold outline-none focus:ring-2 focus:ring-blood-500" placeholder="BLOOD-KEY-XXX" />
                  <Button onClick={handleVerify} className="px-6 py-3 rounded-xl font-black text-xs uppercase">Verify</Button>
                </div>
              </div>
            )}
         </div>

         <div className="lg:col-span-2 space-y-6">
            {/* Real Stats Section */}
            <div className="grid grid-cols-2 gap-6">
               <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 group hover:shadow-xl transition-all">
                  <div className="bg-blood-50 p-3 rounded-2xl w-fit text-blood-600 mb-4 group-hover:scale-110 transition-transform">
                    <Droplet size={24} />
                  </div>
                  <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total Units Donated</p>
                  <p className="text-5xl font-black text-gray-900">{stats.totalUnits}</p>
               </div>
               <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 group hover:shadow-xl transition-all">
                  <div className="bg-green-50 p-3 rounded-2xl w-fit text-green-600 mb-4 group-hover:scale-110 transition-transform">
                    <Heart size={24} />
                  </div>
                  <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Lives Impacted</p>
                  <p className="text-5xl font-black text-green-600">{stats.livesImpacted}</p>
