                      min="1" 
                      value={donationForm.units} 
                      onChange={e => setDonationForm({...donationForm, units: Number(e.target.value)})}
                      className="w-full p-4 bg-gray-50 rounded-2xl text-sm font-black border-none outline-none focus:ring-2 focus:ring-blood-500" 
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Target Date</label>
                    <input 
