            </div>
         </div>
       </div>
    </div>
  );

  const renderRequests = () => (
    <div className="space-y-6 animate-fade-in-up">
      <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 flex justify-between items-center">
