              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                 <div className="flex items-center gap-6">
                    <div className="w-16 h-16 rounded-2xl bg-gray-900 text-white flex items-center justify-center font-black text-2xl shadow-lg">
                       {req.bloodType}
                    </div>
                    <div>
                       <h3 className="font-black text-xl text-gray-900">{req.requesterName}</h3>
                       <p className="text-sm text-gray-500 flex items-center gap-1 font-medium mt-1"><MapPin size={14} className="text-blood-600"/> {req.location} • {req.distance}</p>
                    </div>
                 </div>
                 <div className="flex items-center gap-6 w-full md:w-auto">
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${req.urgency === 'Critical' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'}`}>{req.urgency}</span>
                    <Button className="flex-1 md:flex-none px-8 py-3 rounded-xl font-black uppercase tracking-widest text-xs" onClick={() => openBookingModal(req)}>Respond</Button>
                 </div>
              </div>
           </div>
         ))}
      </div>
    </div>
  );

  const renderEmergency = () => (
    <div className="space-y-8 animate-fade-in-up">
       <div className="bg-gray-900 text-white p-10 rounded-[3rem] shadow-xl relative overflow-hidden">
         <div className="relative z-10">
