         <div className="absolute -top-10 -right-10 w-64 h-64 bg-blood-600 rounded-full blur-[120px] opacity-20"></div>
       </div>
       <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
         {emergencyKeys.map(key => (
           <div key={key.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 flex justify-between items-center hover:shadow-xl transition-all border-l-8 border-l-blood-600">
              <div>
                 <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-2">{key.type} Network Key</p>
                 <p className="font-mono text-3xl font-black text-gray-900 tracking-wider">{key.code}</p>
              </div>
              <div className="text-center bg-gray-50 p-4 rounded-2xl border border-gray-100 min-w-[100px]">
                 <div className="text-4xl font-black text-blood-600 leading-tight">{key.usesRemaining}</div>
                 <div className="text-[9px] text-gray-400 uppercase font-black tracking-widest">Activations</div>
              </div>
           </div>
         ))}
       </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-fade-in-up">
       <div className="flex justify-between items-center bg-white p-8 rounded-[2.5rem] border border-gray-100">
          <div>
            <h2 className="text-2xl font-black text-gray-900 tracking-tight uppercase">Donation Credentials</h2>
            <p className="text-gray-500 font-medium">Download or upload your official certificates.</p>
          </div>
          <Button variant="outline" className="gap-2 px-6 rounded-xl font-black uppercase text-xs" onClick={handleFileUpload}><Upload size={16}/> Upload New</Button>
       </div>
       <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {certificates.map(cert => (
            <div key={cert.id} className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl transition-all group">
