                  <FileText size={48} className="text-gray-300 group-hover:text-blood-300 transition-colors" />
               </div>
               <h4 className="font-black text-gray-900 text-lg">{cert.hospitalName}</h4>
               <p className="text-sm text-gray-500 flex items-center gap-1 font-medium mt-2"><Calendar size={14} className="text-blood-600"/> Verified on {cert.date}</p>
            </div>
          ))}
          {certificates.length === 0 && (
            <div className="col-span-full py-24 text-center">
               <Award size={64} className="mx-auto text-gray-200 mb-6" />
               <p className="text-gray-400 font-black uppercase tracking-widest">Your trophy cabinet is empty</p>
            </div>
          )}
       </div>
    </div>
  );

  const renderRegistration = () => (
    <div className="max-w-4xl mx-auto animate-fade-in-up space-y-8">
       <div className="bg-white rounded-[3rem] shadow-2xl border border-gray-100 overflow-hidden">
          <div className="bg-blood-600 p-10 text-white">
             <h2 className="text-3xl font-black uppercase tracking-tight mb-2">Medical Screening</h2>
             <p className="text-blood-100 font-medium">Verify your medical eligibility status for donation.</p>
          </div>
          <div className="p-10 space-y-10">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="p-6 rounded-2xl bg-gray-50 border border-gray-100 space-y-3">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Weight (KG)</p>
                   <input type="number" defaultValue="70" className="w-full p-4 bg-white rounded-xl border border-gray-100 font-bold" />
                </div>
                <div className="p-6 rounded-2xl bg-gray-50 border border-gray-100 space-y-3">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Last Donation Date</p>
                   <input type="date" className="w-full p-4 bg-white rounded-xl border border-gray-100 font-bold" />
                </div>
             </div>
             <div className="space-y-4">
                <h4 className="font-black text-gray-900 uppercase text-xs tracking-widest">Medical History Check</h4>
