         <button onClick={() => setActiveTab('requests')} className={`px-8 py-4 rounded-2xl text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'requests' ? 'bg-blood-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Requests Feed</button>
         <button onClick={() => setActiveTab('emergency')} className={`px-8 py-4 rounded-2xl text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'emergency' ? 'bg-gray-900 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Emergency Access</button>
         <button onClick={() => setActiveTab('certificates')} className={`px-8 py-4 rounded-2xl text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'certificates' ? 'bg-blue-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Certificates</button>
         <button onClick={() => setActiveTab('registration')} className={`px-8 py-4 rounded-2xl text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'registration' ? 'bg-green-600 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-50'}`}>Profile & Screening</button>
