               <div className="absolute inset-0 bg-gradient-to-br from-blood-600 via-blood-700 to-blood-900"></div>
               <div className="relative z-10 p-8 flex flex-col justify-between h-full text-white">
                 <div className="flex justify-between items-start">
                   <div>
                     <p className="text-[10px] uppercase font-black tracking-[0.2em] opacity-70 mb-1">Authenticated Donor</p>
                     <h3 className="font-black text-2xl tracking-tight">{user.name}</h3>
                   </div>
                   {isVerified ? (
                     <div className="bg-green-500/30 p-2.5 rounded-2xl backdrop-blur-md border border-white/20">
                       <CheckCircle size={20} className="text-green-400" />
                     </div>
                   ) : <Lock className="text-white/30" />}
                 </div>
                 <div className="flex items-end justify-between">
                   <div className="bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl p-4 text-center min-w-[80px] shadow-lg">
                     <p className="text-[9px] font-black opacity-60 uppercase mb-1">Group</p>
                     <p className="text-3xl font-black">{user.bloodType || 'O+'}</p>
                   </div>
                   <div className="text-right">
                     <p className="text-xs font-bold opacity-80">{user.location || 'NYC'}</p>
                     <p className="text-[10px] font-black uppercase tracking-widest opacity-40 mt-1">Node: {user.id.split('-')[1] || 'ADMIN-GEN'}</p>
                   </div>
                 </div>
               </div>
            </div>

            {!isVerified && (
              <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100">
                <h3 className="font-black text-gray-900 mb-4 flex items-center gap-2 uppercase text-xs tracking-widest"><Lock size={16} className="text-yellow-500" /> Account Security</h3>
                <div className="space-y-3">
                  <input type="text" value={specialKey} onChange={(e) => setSpecialKey(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl px-4 py-4 text-sm font-bold outline-none focus:ring-2 focus:ring-blood-500" placeholder="ENTER BLOOD-KEY-XXX" />
                  <Button onClick={handleVerify} className="w-full py-4 rounded-xl font-black text-xs uppercase tracking-widest">Verify ID</Button>
                </div>
              </div>
            )}

            <div className="bg-gray-900 text-white p-8 rounded-[2rem] shadow-xl">
               <div className="flex items-center gap-3 mb-4">
                  <Award className="text-blood-400" />
                  <h4 className="font-black uppercase text-xs tracking-widest">Rank & Achievements</h4>
               </div>
               <div className="space-y-4">
                  <div className="flex justify-between items-center text-sm">
                     <span className="font-bold text-gray-400">Donor Level</span>
                     <span className="font-black text-blood-400">Elite IV</span>
                  </div>
                  <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden">
                     <div className="h-full bg-blood-600 w-3/4 rounded-full"></div>
                  </div>
                  <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">750 XP to Next Level</p>
               </div>
            </div>
         </div>

         <div className="lg:col-span-2 space-y-6">
            <div className="grid grid-cols-2 gap-6">
               <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100 group hover:shadow-xl transition-all relative overflow-hidden">
                  <div className="absolute -right-4 -top-4 opacity-[0.03] group-hover:opacity-[0.06] transition-opacity">
