  Send, Minus, ChevronDown, Heart, ShieldCheck, 
  LogIn, Database, CheckCircle, AlertTriangle, Mic, Camera, BrainCircuit, Headphones, Loader2, UserPlus
} from 'lucide-react';
import { User, UserRole } from './types';
