type ViewState = 'landing' | 'login' | 'register' | 'dashboard';

const SamratBot: React.FC<{ user: User | null }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ sender: 'user' | 'bot', text: string }[]>([
    { sender: 'bot', text: `Namaste! I'm Samrat. How can I help you today?` }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isOpen]);

  const handleSend = async (overrideMsg?: string) => {
    const userMsg = overrideMsg || input;
    if (!userMsg.trim()) return;

    setMessages(prev => [...prev, { sender: 'user', text: userMsg }]);
    if (!overrideMsg) setInput('');
    setIsLoading(true);

    const context = user ? `Role: ${user.role}, Name: ${user.name}` : "Guest";
    const response = await chatWithSamrat(userMsg, context, isThinking);

    setMessages(prev => [...prev, { sender: 'bot', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 bg-white rounded-2xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col h-[500px] animate-fade-in-up">
          <div className="bg-blood-600 p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">🤖</div>
              <h3 className="font-bold">Samrat AI</h3>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-1.5 rounded-lg"><Minus size={18} /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm ${
                  msg.sender === 'user' 
                    ? 'bg-blood-600 text-white rounded-tr-none' 
                    : 'bg-white border text-gray-800 rounded-tl-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex items-center gap-2 pl-2">
                <Loader2 size={14} className="animate-spin text-blood-600" />
                <p className="text-xs text-gray-400 font-medium">Thinking...</p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-4 bg-white border-t flex gap-2">
            <input 
              value={input} 
              onChange={e => setInput(e.target.value)} 
              onKeyPress={e => e.key === 'Enter' && handleSend()} 
              placeholder="Ask Samrat..." 
              className="flex-1 px-4 py-2 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-blood-500 outline-none text-sm"
            />
            <button 
              onClick={() => handleSend()} 
              className="p-2 bg-blood-600 text-white rounded-xl hover:bg-blood-700 transition-colors shadow-md"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      )}
      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className="bg-blood-600 text-white p-4 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all group"
      >
        <MessageSquare size={28} />
      </button>
    </div>
  );
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('landing');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(false);
  const [authError, setAuthError] = useState('');
  const [notification, setNotification] = useState<string | null>(null);

  const [loginForm, setLoginForm] = useState({ username: '', password: '', role: UserRole.USER });
  const [registerForm, setRegisterForm] = useState({ 
    username: '', 
    password: '', 
    role: UserRole.USER, 
    bloodType: 'O+', 
    location: '', 
    email: '' 
  });

  useEffect(() => {
    const saved = localStorage.getItem('lifeflow_current_user');
    if (saved) {
      setCurrentUser(JSON.parse(saved));
      setCurrentView('dashboard');
    }
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthLoading(true);
    setAuthError('');
    try {
      const user = await API.login(loginForm.username, loginForm.password, loginForm.role);
      if (user) {
        setCurrentUser(user);
        localStorage.setItem('lifeflow_current_user', JSON.stringify(user));
        setCurrentView('dashboard');
        setNotification(`Welcome, ${user.name}!`);
        setTimeout(() => setNotification(null), 3000);
      } else {
        setAuthError('Invalid username or password.');
      }
    } catch (err) {
      setAuthError('Authentication failed.');
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthLoading(true);
    setAuthError('');
    try {
      const user = await API.register({ ...registerForm, name: registerForm.username });
      setCurrentUser(user);
      localStorage.setItem('lifeflow_current_user', JSON.stringify(user));
      setCurrentView('dashboard');
      setNotification("Welcome to the network!");
      setTimeout(() => setNotification(null), 3000);
    } catch (err: any) {
      setAuthError(err.message || "Registration failed.");
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('lifeflow_current_user');
    setCurrentView('landing');
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900">
      <nav className={`fixed w-full z-40 transition-all duration-300 ${currentView === 'landing' ? 'bg-gray-900/90 py-5' : 'bg-white/90 backdrop-blur-md border-b py-4'}`}>
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setCurrentView(currentUser ? 'dashboard' : 'landing')}>
            <div className="bg-blood-600 text-white p-2 rounded-xl shadow-lg"><Droplet size={24}/></div>
            <span className={`text-xl font-black tracking-tighter ${currentView === 'landing' ? 'text-white' : 'text-gray-900'}`}>BloodBank</span>
          </div>

          <div className="flex items-center gap-4">
            {!currentUser ? (
              <div className="flex gap-4">
                <button 
                  onClick={() => setCurrentView('login')} 
                  className={`font-bold text-sm ${currentView === 'landing' ? 'text-white' : 'text-gray-600'}`}
                >
                  Login
                </button>
                <Button onClick={() => setCurrentView('register')} className="text-sm">Sign Up</Button>
              </div>
            ) : (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-sm font-black text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <button onClick={handleLogout} className="text-gray-400 hover:text-red-600 transition-colors">
                  <LogOut size={20}/>
                </button>
              </div>
            )}
          </div>
        </div>
      </nav>

      <div className="pt-24 lg:pt-32">
        <SamratBot user={currentUser} />
        {notification && (
          <div className="fixed top-28 right-6 bg-gray-900 text-white p-4 rounded-xl shadow-2xl animate-fade-in-up z-50 flex items-center gap-3 border border-white/10">
            <CheckCircle size={18} className="text-green-500"/>
            <p className="font-bold text-sm">{notification}</p>
          </div>
        )}

        {currentView === 'landing' && <LandingPage onNavigate={setCurrentView} />}

        {(currentView === 'login' || currentView === 'register') && (
          <div className="min-h-[70vh] flex items-center justify-center p-6 animate-fade-in-up">
            <div className="bg-white p-10 rounded-3xl shadow-xl w-full max-w-md border border-gray-100">
              <button onClick={() => setCurrentView('landing')} className="mb-6 text-gray-400 hover:text-gray-800 flex items-center gap-2 font-bold text-xs"><ArrowLeft size={14}/> Back</button>

              <h2 className="text-3xl font-black text-gray-900 mb-2">{currentView === 'login' ? 'Login' : 'Create Account'}</h2>
              <p className="text-gray-500 text-sm mb-8">Access the secure blood management network.</p>

              <form onSubmit={currentView === 'login' ? handleLogin : handleRegister} className="space-y-4">
                {currentView === 'login' && (
                   <select 
                    value={loginForm.role} 
                    onChange={e => setLoginForm({...loginForm, role: e.target.value as UserRole})}
                    className="w-full p-4 bg-gray-50 rounded-xl outline-none font-bold text-sm border-none mb-2"
                   >
                     <option value={UserRole.ADMIN}>Administrator</option>
                     <option value={UserRole.DONOR}>Blood Donor</option>
                     <option value={UserRole.USER}>Recipient / Public</option>
                   </select>
                )}

                {currentView === 'register' && (
                  <div className="flex gap-2 p-1 bg-gray-100 rounded-xl mb-4">
                    <button type="button" onClick={() => setRegisterForm({...registerForm, role: UserRole.USER})} className={`flex-1 py-2 rounded-lg text-xs font-bold ${registerForm.role === UserRole.USER ? 'bg-white shadow-sm text-blood-600' : 'text-gray-500'}`}>Recipient</button>
                    <button type="button" onClick={() => setRegisterForm({...registerForm, role: UserRole.DONOR})} className={`flex-1 py-2 rounded-lg text-xs font-bold ${registerForm.role === UserRole.DONOR ? 'bg-white shadow-sm text-blood-600' : 'text-gray-500'}`}>Donor</button>
                  </div>
                )}

                <input 
                  type="text" 
                  placeholder="Username" 
                  value={currentView === 'login' ? loginForm.username : registerForm.username} 
                  onChange={e => currentView === 'login' ? setLoginForm({...loginForm, username: e.target.value}) : setRegisterForm({...registerForm, username: e.target.value})} 
                  className="w-full p-4 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-blood-500 text-sm" 
                  required 
                />

                <input 
                  type="password" 
                  placeholder="Password" 
                  value={currentView === 'login' ? loginForm.password : registerForm.password} 
                  onChange={e => currentView === 'login' ? setLoginForm({...loginForm, password: e.target.value}) : setRegisterForm({...registerForm, password: e.target.value})} 
                  className="w-full p-4 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-blood-500 text-sm" 
                  required 
                />

                {authError && <div className="p-3 bg-red-50 text-red-600 text-xs font-bold rounded-lg flex items-center gap-2"><AlertTriangle size={14}/> {authError}</div>}

                <Button isLoading={isAuthLoading} className="w-full py-4 text-sm font-black uppercase tracking-widest">
                   {currentView === 'login' ? 'Enter Portal' : 'Register Now'}
                </Button>

                <button type="button" onClick={() => setCurrentView(currentView === 'login' ? 'register' : 'login')} className="w-full text-center text-xs text-blood-600 font-bold hover:underline">
                  {currentView === 'login' ? "New here? Create an account" : "Already have an account? Login"}
                </button>
              </form>
            </div>
          </div>
        )}

        {currentView === 'dashboard' && currentUser && (
          <main className="container mx-auto px-6 py-10 animate-fade-in-up">
            {currentUser.role === UserRole.ADMIN ? <AdminPanel /> : currentUser.role === UserRole.DONOR ? <DonorPanel user={currentUser} /> : <UserPanel />}
          </main>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Heart, Calendar, CheckCircle, Lock, MapPin, Activity, Droplet, PlusCircle, Send, X, Clock, Award } from 'lucide-react';
import { User, BloodRequest, DonationRequest } from '../types';
import { API } from '../services/api';
import { Button } from './Button';

interface DonorPanelProps {
  user: User;
}

type ActiveTab = 'dashboard' | 'requests' | 'history';

export const DonorPanel: React.FC<DonorPanelProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<ActiveTab>('dashboard');
  const [bloodRequests, setBloodRequests] = useState<BloodRequest[]>([]);
  const [isSubmittingDonation, setIsSubmittingDonation] = useState(false);
  const [stats, setStats] = useState({ units: 0, lives: 0 });

  const [donationForm, setDonationForm] = useState({
    units: 1,
    date: new Date().toISOString().split('T')[0],
    isFit: false,
    location: user.location || ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [allReqs, needs] = await Promise.all([
        API.getDonationRequests(),
        API.getBloodNeeds()
      ]);
      setBloodRequests(needs);
      const myDonations = allReqs.filter(r => r.donorName === user.username && r.status === 'Completed');
      setStats({
        units: myDonations.reduce((acc, curr) => acc + (curr.units || 0), 0),
        lives: myDonations.reduce((acc, curr) => acc + (curr.livesImpacted || 0), 0)
      });
    } catch (e) {
      console.error(e);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!donationForm.isFit) return alert("Please confirm medical eligibility.");
    setIsSubmittingDonation(true);
    try {
      await API.addDonationRequest({
        id: `don-${Date.now()}`,
        donorName: user.username,
        bloodType: user.bloodType || 'O+',
        status: 'Pending',
        date: donationForm.date,
        urgency: 'Medium',
        location: donationForm.location,
        type: 'Donation',
        units: donationForm.units
      });
      alert("Registration successful! Admin will review your donation.");
      setDonationForm(prev => ({ ...prev, date: '', isFit: false }));
      loadData();
    } catch (e) {
      alert("Failed to submit.");
    } finally {
      setIsSubmittingDonation(false);
    }
  };

  const renderDashboard = () => (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fade-in-up">
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-gradient-to-br from-blood-600 to-blood-800 p-8 rounded-[2rem] text-white shadow-xl">
           <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">Donor Identity</p>
           <h3 className="text-2xl font-black mb-6">{user.name}</h3>
           <div className="flex items-end justify-between">
              <div className="bg-white/20 backdrop-blur-md rounded-xl p-3 text-center min-w-[60px]">
                 <span className="text-2xl font-black">{user.bloodType || 'O+'}</span>
              </div>
              <p className="text-xs font-bold opacity-80">{user.location || 'NYC'}</p>
           </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white p-6 rounded-[1.5rem] border shadow-sm">
             <Droplet className="text-blood-600 mb-2" size={20}/>
             <p className="text-2xl font-black">{stats.units}</p>
             <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Units Donated</p>
          </div>
          <div className="bg-white p-6 rounded-[1.5rem] border shadow-sm">
             <Heart className="text-green-600 mb-2" size={20}/>
             <p className="text-2xl font-black">{stats.lives}</p>
             <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Lives Impacted</p>
          </div>
        </div>
      </div>

      <div className="lg:col-span-2">
        <div className="bg-white p-8 rounded-[2rem] border shadow-sm">
           <h3 className="text-xl font-black mb-6 flex items-center gap-2"><PlusCircle size={20} className="text-blood-600"/> Register New Donation</h3>
           <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div>
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Donation Units</label>
                    <input type="number" min="1" value={donationForm.units} onChange={e => setDonationForm({...donationForm, units: Number(e.target.value)})} className="w-full p-4 bg-gray-50 rounded-xl border-none text-sm font-bold focus:ring-2 focus:ring-blood-500" />
                 </div>
                 <div>
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Preferred Date</label>
                    <input type="date" required value={donationForm.date} onChange={e => setDonationForm({...donationForm, date: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl border-none text-sm font-bold focus:ring-2 focus:ring-blood-500" />
                 </div>
              </div>
              <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-xl">
                 <input type="checkbox" id="fit" checked={donationForm.isFit} onChange={e => setDonationForm({...donationForm, isFit: e.target.checked})} className="w-5 h-5 text-blood-600 rounded focus:ring-blood-500" />
                 <label htmlFor="fit" className="text-xs font-bold text-gray-600">I confirm that I am medically fit and have not donated in the last 3 months.</label>
              </div>
              <Button type="submit" isLoading={isSubmittingDonation} className="w-full py-4 text-sm font-black uppercase tracking-widest">Submit Registration</Button>
           </form>
        </div>
      </div>
    </div>
  );

  const renderRequests = () => (
    <div className="space-y-6 animate-fade-in-up">
       <div className="bg-white p-8 rounded-[2rem] border shadow-sm flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-black uppercase">Urgent Network Needs</h2>
            <p className="text-gray-500 text-sm">Lives that need your help right now.</p>
          </div>
          <Activity size={32} className="text-blood-600" />
       </div>
       <div className="grid grid-cols-1 gap-4">
          {bloodRequests.map(req => (
            <div key={req.id} className="bg-white p-6 rounded-[1.5rem] border shadow-sm hover:shadow-md transition-shadow">
               <div className="flex justify-between items-center">
                  <div className="flex items-center gap-4">
                     <div className="w-12 h-12 rounded-xl bg-gray-900 text-white flex items-center justify-center font-black text-xl">{req.bloodType}</div>
                     <div>
                        <h4 className="font-black text-gray-900">{req.requesterName}</h4>
                        <p className="text-xs text-gray-400 font-bold uppercase"><MapPin size={10} className="inline mr-1"/>{req.location}</p>
                     </div>
                  </div>
                  <Button className="text-xs px-6 py-2 rounded-lg font-black uppercase" onClick={() => alert("Interest recorded. Admin will contact you.")}>Help Now</Button>
               </div>
            </div>
          ))}
       </div>
    </div>
  );

  return (
    <div className="space-y-8 pb-12">
      <div className="bg-white p-2 rounded-2xl shadow-sm border inline-flex gap-2">
         <button onClick={() => setActiveTab('dashboard')} className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'dashboard' ? 'bg-gray-900 text-white shadow-lg' : 'text-gray-400 hover:bg-gray-50'}`}>Dashboard</button>
         <button onClick={() => setActiveTab('requests')} className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'requests' ? 'bg-blood-600 text-white shadow-lg' : 'text-gray-400 hover:bg-gray-50'}`}>Live Needs</button>
      </div>

      <div className="min-h-[500px]">
         {activeTab === 'dashboard' && renderDashboard()}
         {activeTab === 'requests' && renderRequests()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Users, Activity, MessageSquare, ShieldCheck, RefreshCcw, CheckCircle2, Droplet, UserCheck, Search, Building2 } from 'lucide-react';
import { User, DonationRequest, Feedback, BloodStock } from '../types';
import { API } from '../services/api';
import { Button } from './Button';

type AdminTab = 'dashboard' | 'users' | 'requests';

export const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('dashboard');
  const [users, setUsers] = useState<User[]>([]);
  const [requests, setRequests] = useState<DonationRequest[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = async () => {
    setIsRefreshing(true);
    try {
      const [u, r] = await Promise.all([
        API.getUsers(),
        API.getDonationRequests()
      ]);
      setUsers(u);
      setRequests(r);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRefreshing(false);
    }
  };

  const handleStatusUpdate = async (id: string, status: 'Completed', impact: number) => {
    try {
      await API.updateDonationRequestStatus(id, status, impact);
      refreshData();
      alert("Status updated successfully.");
    } catch (e) {
      alert("Update failed.");
    }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-fade-in-up">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-[2rem] border shadow-sm">
           <Users className="text-blue-600 mb-4" size={24} />
           <p className="text-3xl font-black">{users.length}</p>
           <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Network Users</p>
        </div>
        <div className="bg-white p-8 rounded-[2rem] border shadow-sm">
           <Activity className="text-blood-600 mb-4" size={24} />
           <p className="text-3xl font-black">{requests.filter(r => r.status === 'Pending').length}</p>
           <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Pending Tasks</p>
        </div>
        <div className="bg-white p-8 rounded-[2rem] border shadow-sm">
           <ShieldCheck className="text-green-600 mb-4" size={24} />
           <p className="text-3xl font-black">Active</p>
           <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">System Health</p>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm overflow-hidden">
         <div className="flex justify-between items-center mb-8">
            <h3 className="text-xl font-black uppercase tracking-tight flex items-center gap-2"><Droplet className="text-blood-600"/> Donation Registry Feed</h3>
            <Button variant="outline" className="text-xs h-auto py-1 px-4 gap-2" onClick={refreshData} isLoading={isRefreshing}><RefreshCcw size={14}/> Sync</Button>
         </div>
         <div className="overflow-x-auto">
            <table className="w-full text-left">
               <thead>
                  <tr className="text-[10px] font-black text-gray-400 uppercase tracking-widest border-b">
                     <th className="pb-4">Donor</th>
                     <th className="pb-4">Group</th>
                     <th className="pb-4">Location</th>
                     <th className="pb-4">Units</th>
                     <th className="pb-4 text-right">Action</th>
                  </tr>
               </thead>
               <tbody className="text-sm">
                  {requests.filter(r => r.type === 'Donation').map(req => (
                    <tr key={req.id} className="border-b last:border-0">
                       <td className="py-4 font-bold">{req.donorName}</td>
                       <td className="py-4"><span className="px-2 py-1 bg-blood-50 text-blood-700 rounded text-[10px] font-black">{req.bloodType}</span></td>
                       <td className="py-4 text-gray-500">{req.location}</td>
                       <td className="py-4 font-black">{req.units}</td>
                       <td className="py-4 text-right">
                          {req.status === 'Pending' ? (
                            <button onClick={() => {
                              const imp = prompt("How many lives were impacted?", "3");
                              if (imp) handleStatusUpdate(req.id, 'Completed', Number(imp));
                            }} className="px-4 py-1.5 rounded-full text-[10px] font-black uppercase bg-blood-600 text-white shadow-md">Complete</button>
                          ) : (
                            <span className="text-green-600 font-black text-[10px] uppercase">Verified Done</span>
                          )}
                       </td>
                    </tr>
                  ))}
               </tbody>
            </table>
         </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <div className="bg-white p-2 rounded-2xl border inline-flex gap-2">
         <button onClick={() => setActiveTab('dashboard')} className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'dashboard' ? 'bg-gray-900 text-white' : 'text-gray-400'}`}>System Console</button>
         <button onClick={() => setActiveTab('users')} className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>User Base</button>
      </div>
      {activeTab === 'dashboard' && renderDashboard()}
      {activeTab === 'users' && <div className="bg-white p-10 rounded-3xl border text-center text-gray-400 font-bold">User database synced. Actions available soon.</div>}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Search, MapPin, Droplet, Activity, Info, PlusCircle, Building2, Phone, AlertCircle } from 'lucide-react';
import { User, UserRole, DonationRequest } from '../types';
import { API } from '../services/api';
import { findDonorsWithAI } from '../services/geminiService';
import { Button } from './Button';

export const UserPanel: React.FC = () => {
  const [bloodType, setBloodType] = useState('All');
  const [city, setCity] = useState('');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showForm, setShowForm] = useState(false);

  const [requestForm, setRequestForm] = useState({
    name: '',
    bloodType: 'O+',
    hospital: '',
    city: '',
    phone: ''
  });

  const handleSearch = async () => {
    setIsSearching(true);
    setSearchResults([]);
    try {
      const results = await findDonorsWithAI(bloodType, city);
      setSearchResults(results);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSearching(false);
    }
  };

  const handleRequestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await API.addDonationRequest({
        id: `req-${Date.now()}`,
        donorName: requestForm.name,
        bloodType: requestForm.bloodType,
        status: 'Pending',
        date: new Date().toLocaleDateString(),
        urgency: 'Medium',
        hospital: requestForm.hospital,
        location: requestForm.city,
        phone: requestForm.phone,
        type: 'Request'
      });
      alert("Emergency request registered! Admins notified.");
      setShowForm(false);
    } catch (e) {
      alert("Error.");
    }
  };

  return (
    <div className="space-y-10 animate-fade-in-up">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-gray-100 overflow-hidden">
         <div className="flex justify-between items-center mb-8">
            <h2 className="text-2xl font-black uppercase flex items-center gap-2"><Search className="text-blood-600"/> Blood Search Engine</h2>
            <Button variant="outline" onClick={() => setShowForm(!showForm)} className="text-xs py-2 px-6 rounded-xl font-black uppercase">{showForm ? 'Cancel' : 'Post Request'}</Button>
         </div>

         {!showForm ? (
            <div className="space-y-8">
               <div className="flex flex-col md:flex-row gap-4">
                  <select value={bloodType} onChange={e => setBloodType(e.target.value)} className="flex-1 p-4 bg-gray-50 rounded-2xl outline-none font-bold border-none shadow-inner">
                     <option value="All">All Groups</option>
                     {['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'].map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                  <input type="text" placeholder="Enter City..." value={city} onChange={e => setCity(e.target.value)} className="flex-[2] p-4 bg-gray-50 rounded-2xl outline-none font-bold border-none shadow-inner" />
                  <Button onClick={handleSearch} isLoading={isSearching} className="px-10 py-4 font-black uppercase rounded-2xl">Initialize Scan</Button>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {searchResults.map(donor => (
                    <div key={donor.id} className="bg-white p-6 rounded-[2rem] border shadow-sm hover:shadow-lg transition-all">
                       <div className="flex items-center gap-4 mb-4">
                          <div className="w-12 h-12 rounded-xl bg-blood-50 text-blood-700 flex items-center justify-center font-black text-lg">{donor.bloodType}</div>
                          <div>
                             <h4 className="font-black text-gray-900">{donor.name}</h4>
                             <p className="text-xs text-gray-400 font-bold uppercase"><MapPin size={10} className="inline mr-1"/>{donor.location}</p>
                          </div>
                       </div>
                       <Button className="w-full py-2 text-xs font-black uppercase rounded-lg" onClick={() => alert("Request sent to donor.")}>Contact Donor</Button>
                    </div>
                  ))}
               </div>
            </div>
         ) : (
            <form onSubmit={handleRequestSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in-up">
               <input type="text" placeholder="Patient Name" required value={requestForm.name} onChange={e => setRequestForm({...requestForm, name: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl font-bold border-none" />
               <select value={requestForm.bloodType} onChange={e => setRequestForm({...requestForm, bloodType: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl font-bold border-none">
                  {['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'].map(t => <option key={t} value={t}>{t}</option>)}
               </select>
               <input type="text" placeholder="Hospital" required value={requestForm.hospital} onChange={e => setRequestForm({...requestForm, hospital: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl font-bold border-none" />
               <input type="text" placeholder="City" required value={requestForm.city} onChange={e => setRequestForm({...requestForm, city: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl font-bold border-none" />
               <input type="tel" placeholder="Phone" required value={requestForm.phone} onChange={e => setRequestForm({...requestForm, phone: e.target.value})} className="w-full p-4 bg-gray-50 rounded-xl font-bold border-none" />
               <Button type="submit" className="md:col-span-2 py-4 font-black uppercase rounded-xl">Register Emergency Request</Button>
            </form>
         )}
      </div>
    </div>
  );
};
